  1→package cmd
  2→
  3→import (
  4→	"fmt"
  5→	"os"
  6→	"path/filepath"
  7→	"strings"
  8→
  9→	nurgeInit "github.com/usenurge/nurgesh/internal/init"
 10→	"github.com/spf13/cobra"
 11→)
 12→
 13→var (
 14→	initCredentials string
 15→	initSkipConnect bool
 16→	initSkipHooks   bool
 17→	initForce       bool
 18→	initVerbose     bool
 19→)
 20→
 21→var initCmd = &cobra.Command{
 22→	Use:         "init [directory]",
 23→	Short:       "Initialize a nurge project",
 24→	Long:        "Sets up .nurge/ directory, database, connectors, Claude Code hooks, and the /nurge:setup skill.",
 25→	Args:        cobra.MaximumNArgs(1),
 26→	Annotations: map[string]string{"skipAuth": "true"},
 27→	RunE: func(cmd *cobra.Command, args []string) error {
 28→		dirCreated := ""
 29→
 30→		if len(args) == 1 {
 31→			// nurge init <directory> — create and chdir into it
 32→			dir := args[0]
 33→			if err := os.MkdirAll(dir, 0755); err != nil {
 34→				return fmt.Errorf("failed to create directory %s: %w", dir, err)
 35→			}
 36→			abs, err := filepath.Abs(dir)
 37→			if err != nil {
 38→				return err
 39→			}
 40→			if err := os.Chdir(abs); err != nil {
 41→				return fmt.Errorf("failed to enter directory %s: %w", dir, err)
 42→			}
 43→			dirCreated = dir
 44→		}
 45→
 46→		// Check if current directory is non-empty (unless --force)
 47→		if !initForce {
 48→			empty, err := isDirEmpty(".")
 49→			if err != nil {
 50→				return err
 51→			}
 52→			if !empty {
 53→				return fmt.Errorf("this directory isn't empty. Run: nurge init <folder-name>")
 54→			}
 55→		}
 56→
 57→		opts := nurgeInit.Options{
 58→			Credentials:    initCredentials,
 59→			SkipConnectors: initSkipConnect,
 60→			SkipHooks:      initSkipHooks,
 61→			Force:          initForce,
 62→			Verbose:        initVerbose,
 63→		}
 64→		if err := nurgeInit.Run(opts); err != nil {
 65→			return err
 66→		}
 67→
 68→		if dirCreated != "" {
 69→			fmt.Println()
 70→			fmt.Printf("  Now run: cd %s\n", dirCreated)
 71→			fmt.Println()
 72→		}
 73→
 74→		return nil
 75→	},
 76→}
 77→
 78→// isDirEmpty returns true if dir contains no entries except allowed ones
 79→// (.nurge, .git, .gitignore, .DS_Store, .claude).
 80→func isDirEmpty(dir string) (bool, error) {
 81→	allowed := map[string]bool{
 82→		".nurge":     true,
 83→		".git":       true,
 84→		".gitignore": true,
 85→		".DS_Store":  true,
 86→		".claude":    true,
 87→	}
 88→
 89→	entries, err := os.ReadDir(dir)
 90→	if err != nil {
 91→		return false, err
 92→	}
 93→	for _, e := range entries {
 94→		name := strings.TrimSuffix(e.Name(), "/")
 95→		if !allowed[name] {
 96→			return false, nil
 97→		}
 98→	}
 99→	return true, nil
100→}
101→
102→func init() {
103→	initCmd.Flags().StringVar(&initCredentials, "credentials", "", "Path to OAuth credentials.json for Gmail (default: bundled)")
104→	initCmd.Flags().BoolVar(&initSkipConnect, "skip-connectors", false, "Skip the connector step")
105→	initCmd.Flags().BoolVar(&initSkipHooks, "skip-hooks", false, "Skip Claude Code hook installation")
106→	initCmd.Flags().BoolVar(&initForce, "force", false, "Re-run all steps even if already completed")
107→	initCmd.Flags().BoolVar(&initVerbose, "verbose", false, "Show detailed output")
108→
109→	rootCmd.AddCommand(initCmd)
110→}
