 1→package init
 2→
 3→import (
 4→	"fmt"
 5→	"os"
 6→)
 7→
 8→// Options holds CLI flags for nurge init.
 9→type Options struct {
10→	Credentials    string
11→	SkipConnectors bool
12→	SkipHooks      bool
13→	Force          bool
14→	Verbose        bool
15→}
16→
17→// Step is the interface each init step implements.
18→type Step interface {
19→	Name() string
20→	Done() (bool, error)
21→	Run() error
22→}
23→
24→// Run executes all init steps in order.
25→func Run(opts Options) error {
26→	fmt.Println()
27→	fmt.Println("  nurge — outbound that learns")
28→	fmt.Println()
29→
30→	steps := buildSteps(opts)
31→
32→	for _, s := range steps {
33→		if !opts.Force {
34→			done, err := s.Done()
35→			if err != nil {
36→				printFail(s.Name(), err)
37→				return err
38→			}
39→			if done {
40→				printSkip(s.Name())
41→				continue
42→			}
43→		}
44→
45→		if err := s.Run(); err != nil {
46→			printFail(s.Name(), err)
47→			return err
48→		}
49→		printDone(s.Name())
50→	}
51→
52→	return nil
53→}
54→
55→func buildSteps(opts Options) []Step {
56→	var steps []Step
57→
58→	steps = append(steps, &projectStep{})
59→	steps = append(steps, &databaseStep{})
60→	steps = append(steps, &gitignoreStep{})
61→
62→	if !opts.SkipConnectors {
63→		steps = append(steps, &connectStep{credentials: opts.Credentials})
64→	}
65→
66→	if !opts.SkipHooks {
67→		steps = append(steps, &hooksStep{})
68→	}
69→
70→	steps = append(steps, &skillStep{})
71→	steps = append(steps, &gitStep{})
72→	steps = append(steps, &nextStepStep{})
73→
74→	return steps
75→}
76→
77→func printDone(name string) {
78→	fmt.Fprintf(os.Stdout, "  \033[32m✓\033[0m %s\n", name)
79→}
80→
81→func printSkip(name string) {
82→	fmt.Fprintf(os.Stdout, "  \033[32m✓\033[0m %s (already done)\n", name)
83→}
84→
85→func printFail(name string, err error) {
86→	fmt.Fprintf(os.Stderr, "  \033[31m✗\033[0m %s: %v\n", name, err)
87→}
88→

  1→package init
  2→
  3→import (
  4→	"bufio"
  5→	"context"
  6→	"fmt"
  7→	"os"
  8→	"strings"
  9→
 10→	"github.com/usenurge/nurgesh/internal/config"
 11→	"github.com/usenurge/nurgesh/internal/connector"
 12→)
 13→
 14→type connectStep struct {
 15→	credentials string
 16→}
 17→
 18→func (s *connectStep) Name() string { return "Stack connected" }
 19→
 20→func (s *connectStep) Done() (bool, error) {
 21→	cfg, err := config.Load()
 22→	if err != nil {
 23→		return false, nil // config might not exist yet in a fresh run
 24→	}
 25→	// Done if at least Gmail is connected
 26→	if cs, ok := cfg.Connectors["gmail"]; ok && cs.Connected {
 27→		return true, nil
 28→	}
 29→	return false, nil
 30→}
 31→
 32→func (s *connectStep) Run() error {
 33→	cfg, err := config.Load()
 34→	if err != nil {
 35→		return fmt.Errorf("loading config: %w", err)
 36→	}
 37→
 38→	registry := connector.DefaultRegistry()
 39→	reader := bufio.NewReader(os.Stdin)
 40→
 41→	fmt.Println()
 42→	fmt.Println("  Connect your stack:")
 43→
 44→	for {
 45→		// Show menu
 46→		fmt.Println()
 47→		fmt.Println("    Email (required)")
 48→		for i, c := range registry {
 49→			if c.Type != "email" {
 50→				continue
 51→			}
 52→			status := ""
 53→			if cs, ok := cfg.Connectors[c.ID]; ok && cs.Connected {
 54→				status = fmt.Sprintf(" \033[32m✓\033[0m %s", cs.Account)
 55→			}
 56→			fmt.Printf("      [%d] %s%s\n", i+1, c.Name, status)
 57→		}
 58→
 59→		fmt.Println()
 60→		fmt.Println("    CRM (optional — enriches contacts with deal & pipeline data)")
 61→		for i, c := range registry {
 62→			if c.Type != "crm" {
 63→				continue
 64→			}
 65→			status := ""
 66→			if cs, ok := cfg.Connectors[c.ID]; ok && cs.Connected {
 67→				status = fmt.Sprintf(" \033[32m✓\033[0m %s", cs.Account)
 68→			}
 69→			fmt.Printf("      [%d] %s%s\n", i+1, c.Name, status)
 70→		}
 71→
 72→		fmt.Println()
 73→		fmt.Print("    [done] Finish connecting\n\n  > ")
 74→
 75→		input, err := reader.ReadString('\n')
 76→		if err != nil {
 77→			return fmt.Errorf("reading input: %w", err)
 78→		}
 79→		input = strings.TrimSpace(input)
 80→
 81→		if input == "done" {
 82→			// Check Gmail is connected
 83→			if cs, ok := cfg.Connectors["gmail"]; !ok || !cs.Connected {
 84→				fmt.Println()
 85→				fmt.Print("  Gmail is required — it's how nurge reads your outbound history.\n  Connect now? [Y/n] ")
 86→				yn, _ := reader.ReadString('\n')
 87→				yn = strings.TrimSpace(strings.ToLower(yn))
 88→				if yn == "n" || yn == "no" {
 89→					return fmt.Errorf("gmail is required to use nurge")
 90→				}
 91→				input = "1" // fall through to connect Gmail
 92→			} else {
 93→				break
 94→			}
 95→		}
 96→
 97→		// Parse selection
 98→		var idx int
 99→		if _, err := fmt.Sscanf(input, "%d", &idx); err != nil || idx < 1 || idx > len(registry) {
100→			fmt.Println("  Invalid selection. Try again.")
101→			continue
102→		}
103→
104→		def := registry[idx-1]
105→		conn := def.New(s.credentials)
106→
107→		fmt.Printf("  Opening browser for %s...\n", def.Name)
108→
109→		result, err := conn.Connect(context.Background())
110→		if err != nil {
111→			fmt.Printf("  \033[31m✗\033[0m %s: %v\n", def.Name, err)
112→			if def.Required {
113→				return fmt.Errorf("%s connection failed: %w", def.Name, err)
114→			}
115→			fmt.Printf("  Skipping %s. You can connect later with `nurge connect %s`\n", def.Name, def.ID)
116→			continue
117→		}
118→
119→		// Save connector state
120→		if err := config.SetConnector(def.ID, def.Type, result.Account); err != nil {
121→			return fmt.Errorf("saving %s config: %w", def.Name, err)
122→		}
123→
124→		// Reload config
125→		cfg, _ = config.Load()
126→
127→		fmt.Printf("  \033[32m✓\033[0m %s connected (%s)\n", def.Name, result.Account)
128→	}
129→
130→	// Print summary
131→	var connected []string
132→	for _, c := range registry {
133→		if cs, ok := cfg.Connectors[c.ID]; ok && cs.Connected {
134→			connected = append(connected, c.Name)
135→		}
136→	}
137→	fmt.Printf("\n  Connected: %s\n", strings.Join(connected, ", "))
138→
139→	// Tip if no CRM
140→	hasCRM := false
141→	for _, c := range registry {
142→		if c.Type == "crm" {
143→			if cs, ok := cfg.Connectors[c.ID]; ok && cs.Connected {
144→				hasCRM = true
145→				break
146→			}
147→		}
148→	}
149→	if !hasCRM {
150→		fmt.Println("  Tip: You can connect a CRM later with `nurge connect hubspot`")
151→	}
152→
153→	return nil
154→}
