  1→package config
  2→
  3→import (
  4→	"encoding/json"
  5→	"fmt"
  6→	"os"
  7→	"time"
  8→)
  9→
 10→const configFile = ".nurge/config.json"
 11→
 12→// ConnectorState holds the state of a single connected service.
 13→type ConnectorState struct {
 14→	Connected   bool   `json:"connected"`
 15→	ConnectedAt string `json:"connected_at,omitempty"`
 16→	Account     string `json:"account,omitempty"`
 17→	Type        string `json:"type"` // "crm" or "email"
 18→}
 19→
 20→// Config is the top-level nurge configuration.
 21→type Config struct {
 22→	Version        int                        `json:"version"`
 23→	CreatedAt      string                     `json:"created_at"`
 24→	Connectors     map[string]ConnectorState  `json:"connectors"`
 25→	SetupCompleted bool                       `json:"setup_completed"`
 26→	Settings       map[string]string          `json:"settings,omitempty"`
 27→}
 28→
 29→// Path returns the path to config.json.
 30→func Path() string {
 31→	return configFile
 32→}
 33→
 34→// Default returns a new Config with default values.
 35→func Default() *Config {
 36→	return &Config{
 37→		Version:        1,
 38→		CreatedAt:      time.Now().UTC().Format(time.RFC3339),
 39→		Connectors:     make(map[string]ConnectorState),
 40→		SetupCompleted: false,
 41→	}
 42→}
 43→
 44→// Load reads config from disk.
 45→func Load() (*Config, error) {
 46→	data, err := os.ReadFile(configFile)
 47→	if err != nil {
 48→		return nil, fmt.Errorf("reading config: %w", err)
 49→	}
 50→	var cfg Config
 51→	if err := json.Unmarshal(data, &cfg); err != nil {
 52→		return nil, fmt.Errorf("parsing config: %w", err)
 53→	}
 54→	if cfg.Connectors == nil {
 55→		cfg.Connectors = make(map[string]ConnectorState)
 56→	}
 57→	return &cfg, nil
 58→}
 59→
 60→// Write saves config to disk.
 61→func Write(cfg *Config) error {
 62→	data, err := json.MarshalIndent(cfg, "", "  ")
 63→	if err != nil {
 64→		return fmt.Errorf("marshaling config: %w", err)
 65→	}
 66→	if err := os.WriteFile(configFile, data, 0644); err != nil {
 67→		return fmt.Errorf("writing config: %w", err)
 68→	}
 69→	return nil
 70→}
 71→
 72→// SetConnector updates a connector in the config and saves.
 73→func SetConnector(id, connType, account string) error {
 74→	cfg, err := Load()
 75→	if err != nil {
 76→		return err
 77→	}
 78→	cfg.Connectors[id] = ConnectorState{
 79→		Connected:   true,
 80→		ConnectedAt: time.Now().UTC().Format(time.RFC3339),
 81→		Account:     account,
 82→		Type:        connType,
 83→	}
 84→	return Write(cfg)
 85→}
 86→
 87→// RemoveConnector removes a connector from config and saves.
 88→func RemoveConnector(id string) error {
 89→	cfg, err := Load()
 90→	if err != nil {
 91→		return err
 92→	}
 93→	delete(cfg.Connectors, id)
 94→	return Write(cfg)
 95→}
 96→
 97→// Get returns the value for a settings key, or empty string if not set.
 98→func Get(key string) (string, error) {
 99→	cfg, err := Load()
100→	if err != nil {
101→		return "", err
102→	}
103→	if cfg.Settings == nil {
104→		return "", nil
105→	}
106→	return cfg.Settings[key], nil
107→}
108→
109→// Set stores a key/value pair in settings and saves the config.
110→func Set(key, value string) error {
111→	cfg, err := Load()
112→	if err != nil {
113→		return err
114→	}
115→	if cfg.Settings == nil {
116→		cfg.Settings = make(map[string]string)
117→	}
118→	cfg.Settings[key] = value
119→	return Write(cfg)
120→}
