 74→// sessionStatus holds workspace state gathered for banner/prompt output.
 75→type sessionStatus struct {
 76→	configLoaded   bool
 77→	setupCompleted bool
 78→	connectors     map[string]config.ConnectorState
 79→	emailTotal     int
 80→	skillCount     int
 81→	skillNames     []string
 82→}
 83→
 84→func gatherStatus() *sessionStatus {
 85→	s := &sessionStatus{}
 86→
 87→	// Load config (graceful — may not exist)
 88→	cfg, err := config.Load()
 89→	if err == nil {
 90→		s.configLoaded = true
 91→		s.setupCompleted = cfg.SetupCompleted
 92→		s.connectors = cfg.Connectors
 93→	}
 94→
 95→	// Load DB stats (graceful — may not exist)
 96→	if !db.Exists() {
 97→		return s
 98→	}
 99→	d, err := db.Open()
100→	if err != nil {
101→		return s
102→	}
103→	defer d.Close()
104→
105→	stats, err := emails.Stats(d)
106→	if err == nil {
107→		s.emailTotal = stats.Total
108→	}
109→
110→	skills, err := learning.ListSkills(d)
111→	if err == nil {
112→		s.skillCount = len(skills)
113→		for _, sk := range skills {
114→			s.skillNames = append(s.skillNames, sk.SkillName)
115→		}
116→	}
117→
118→	return s
119→}
