121→// hookOutput is the JSON structure Claude Code expects from hook stdout.
122→type hookOutput struct {
123→	SystemMessage    string            `json:"systemMessage,omitempty"`
124→	HookSpecificOut  *hookSpecificOut  `json:"hookSpecificOutput,omitempty"`
125→}
126→
127→type hookSpecificOut struct {
128→	HookEventName     string `json:"hookEventName"`
129→	AdditionalContext string `json:"additionalContext,omitempty"`
130→}
131→
132→// runSessionStart outputs JSON with systemMessage (visible banner) and
133→// additionalContext (LLM context) for the SessionStart hook.
134→// Also captures the session in DB + log.
135→func runSessionStart() error {
136→	// Read stdin (Claude Code sends session info)
137→	input, _ := sessions.ReadStdin()
138→
139→	// Capture session in DB (graceful — don't fail the hook if DB is missing)
140→	if input != nil && input.SessionID != "" && db.Exists() {
141→		if d, err := db.Open(); err == nil {
142→			db.EnsureSessionTables(d)
143→			sessions.CreateSession(d, input.SessionID, input.Model, input.Source, input.TranscriptPath)
144→			sessions.AddEvent(d, input.SessionID, "session_start", input)
145→			d.Close()
146→		}
147→		sessions.Logger().Info("session-start", "session_id", input.SessionID, "model", input.Model)
148→		sessions.FlushLog()
149→	}
150→
151→	s := gatherStatus()
152→
153→	banner := buildBanner(s)
154→	context := buildPromptContext(s)
155→
156→	out := hookOutput{
157→		SystemMessage: banner,
158→		HookSpecificOut: &hookSpecificOut{
159→			HookEventName:     "SessionStart",
160→			AdditionalContext: context,
161→		},
162→	}
163→
164→	enc := json.NewEncoder(os.Stdout)
165→	return enc.Encode(out)
166→}
