168→// runUserPrompt captures a user prompt submission event.
169→func runUserPrompt() error {
170→	input, err := sessions.ReadStdin()
171→	if err != nil || input == nil || input.SessionID == "" {
172→		return nil // graceful no-op
173→	}
174→
175→	if !db.Exists() {
176→		return nil
177→	}
178→	d, err := db.Open()
179→	if err != nil {
180→		return nil
181→	}
182→	defer d.Close()
183→
184→	db.EnsureSessionTables(d)
185→	sessions.AddEvent(d, input.SessionID, "prompt", input)
186→
187→	// Log without prompt content — keep logs lightweight
188→	sessions.Logger().Info("prompt", "session_id", input.SessionID)
189→	sessions.FlushLog()
190→	return nil
191→}
192→
193→// runStop captures a stop event and creates a checkpoint.
194→func runStop() error {
195→	input, err := sessions.ReadStdin()
196→	if err != nil || input == nil || input.SessionID == "" {
197→		return nil
198→	}
199→
200→	if !db.Exists() {
201→		return nil
202→	}
203→	d, err := db.Open()
204→	if err != nil {
205→		return nil
206→	}
207→	defer d.Close()
208→
209→	db.EnsureSessionTables(d)
210→	sessions.AddEvent(d, input.SessionID, "stop", input)
211→	if len(input.ModifiedFiles) > 0 {
212→		sessions.AddCheckpoint(d, input.SessionID, input.ModifiedFiles)
213→	}
214→
215→	sessions.Logger().Info("stop", "session_id", input.SessionID, "reason", input.StopReason)
216→	sessions.FlushLog()
217→	return nil
218→}
219→
220→// runSessionEnd marks a session as ended.
221→func runSessionEnd() error {
222→	input, err := sessions.ReadStdin()
223→	if err != nil || input == nil || input.SessionID == "" {
224→		return nil
225→	}
226→
227→	if !db.Exists() {
228→		return nil
229→	}
230→	d, err := db.Open()
231→	if err != nil {
232→		return nil
233→	}
234→	defer d.Close()
235→
236→	db.EnsureSessionTables(d)
237→	sessions.EndSession(d, input.SessionID)
238→	sessions.AddEvent(d, input.SessionID, "session_end", input)
239→
240→	sessions.Logger().Info("session-end", "session_id", input.SessionID)
241→	sessions.FlushLog()
242→	return nil
243→}
