245→func buildBanner(s *sessionStatus) string {
246→	var b strings.Builder
247→
248→	b.WriteString("\n\nPowered by Nurge:\n")
249→
250→	if !s.configLoaded {
251→		b.WriteString("  Run: nurge init to get started")
252→		return b.String()
253→	}
254→
255→	// Connectors
256→	hasConnectors := false
257→	for id, c := range s.connectors {
258→		if !c.Connected {
259→			continue
260→		}
261→		hasConnectors = true
262→		switch c.Type {
263→		case "email":
264→			fmt.Fprintf(&b, "  %s: %s (%s emails synced)\n", capitalize(id), c.Account, formatCount(s.emailTotal))
265→		case "crm":
266→			fmt.Fprintf(&b, "  %s: connected\n", capitalize(id))
267→		}
268→	}
269→
270→	if !hasConnectors {
271→		b.WriteString("  No connectors configured.\n")
272→		b.WriteString("  Run: nurge init --force to reconnect")
273→		return b.String()
274→	}
275→
276→	// Skills
277→	fmt.Fprintf(&b, "  Skills: %d active\n", s.skillCount)
278→
279→	if s.setupCompleted {
280→		b.WriteString("  Try:\n")
281→		b.WriteString("    \"Write a cold email to the CTO at Datastack\"\n")
282→		b.WriteString("    \"Research Acme Corp and qualify them\"\n")
283→		b.WriteString("    \"Show my pipeline\"")
284→	} else {
285→		b.WriteString("  Run /nurge:setup to get started")
286→	}
287→
288→	return b.String()
289→}
290→
291→func buildPromptContext(s *sessionStatus) string {
292→	var b strings.Builder
293→
294→	if !s.configLoaded || !s.setupCompleted {
295→		b.WriteString("You are in a Nurge workspace. Setup is not complete. ")
296→		b.WriteString("Guide the user to run /nurge:setup to finish configuration. ")
297→		b.WriteString("Do not attempt to use nurge data commands — they will have no data yet.")
298→		return b.String()
299→	}
300→
301→	b.WriteString("You are in a Nurge outbound sales workspace.\n")
302→	fmt.Fprintf(&b, "Status: Setup complete. %s emails synced. %d skills active.\n", formatCount(s.emailTotal), s.skillCount)
303→	b.WriteString("Rules:\n")
304→	b.WriteString("- Use `nurge` CLI commands for all data access. Never read .nurge/ directly.\n")
305→	b.WriteString("- For ICP and product context, run: nurge config show --format json\n")
306→	b.WriteString("- For email patterns and insights, run: nurge context generate --format json\n")
307→	b.WriteString("- For email stats, run: nurge emails stats --format json\n")
308→	b.WriteString("- When writing outbound emails, always run: nurge send")
309→
310→	if len(s.skillNames) > 0 {
311→		fmt.Fprintf(&b, "\nAvailable skills: %s", strings.Join(s.skillNames, ", "))
312→	}
313→
314→	return b.String()
315→}
316→
317→func capitalize(s string) string {
318→	if s == "" {
319→		return s
320→	}
321→	return strings.ToUpper(s[:1]) + s[1:]
322→}
323→
324→func formatCount(n int) string {
325→	if n >= 1000 {
326→		return fmt.Sprintf("%d,%03d", n/1000, n%1000)
327→	}
328→	return fmt.Sprintf("%d", n)
329→}
