 32→export type PluginManifestProviderAuthChoice = {
 33→  /** Provider id owned by this manifest entry. */
 34→  provider: string;
 35→  /** Provider auth method id that this choice should dispatch to. */
 36→  method: string;
 37→  /** Stable auth-choice id used by onboarding and other CLI auth flows. */
 38→  choiceId: string;
 39→  /** Optional user-facing choice label/hint for grouped onboarding UI. */
 40→  choiceLabel?: string;
 41→  choiceHint?: string;
 42→  /** Optional grouping metadata for auth-choice pickers. */
 43→  groupId?: string;
 44→  groupLabel?: string;
 45→  groupHint?: string;
 46→  /** Optional CLI flag metadata for one-flag auth flows such as API keys. */
 47→  optionKey?: string;
 48→  cliFlag?: string;
 49→  cliOption?: string;
 50→  cliDescription?: string;
 51→  /**
 52→   * Interactive onboarding surfaces where this auth choice should appear.
 53→   * Defaults to `["text-inference"]` when omitted.
 54→   */
 55→  onboardingScopes?: PluginManifestOnboardingScope[];
 56→};
 57→
 58→export type PluginManifestOnboardingScope = "text-inference" | "image-generation";
 59→
 60→export type PluginManifestLoadResult =
 61→  | { ok: true; manifest: PluginManifest; manifestPath: string }
 62→  | { ok: false; error: string; manifestPath: string };
 63→
 64→function normalizeStringList(value: unknown): string[] {
 65→  if (!Array.isArray(value)) {
 66→    return [];
 67→  }
 68→  return value.map((entry) => (typeof entry === "string" ? entry.trim() : "")).filter(Boolean);
 69→}
 70→
 71→function normalizeStringListRecord(value: unknown): Record<string, string[]> | undefined {
 72→  if (!isRecord(value)) {
 73→    return undefined;
 74→  }
 75→  const normalized: Record<string, string[]> = {};
 76→  for (const [key, rawValues] of Object.entries(value)) {
 77→    const providerId = typeof key === "string" ? key.trim() : "";
 78→    if (!providerId) {
 79→      continue;
 80→    }
 81→    const values = normalizeStringList(rawValues);
 82→    if (values.length === 0) {
 83→      continue;
 84→    }
 85→    normalized[providerId] = values;
 86→  }
 87→  return Object.keys(normalized).length > 0 ? normalized : undefined;
 88→}
 89→
 90→function normalizeProviderAuthChoices(
 91→  value: unknown,
 92→): PluginManifestProviderAuthChoice[] | undefined {
 93→  if (!Array.isArray(value)) {
 94→    return undefined;
 95→  }
 96→  const normalized: PluginManifestProviderAuthChoice[] = [];
 97→  for (const entry of value) {
 98→    if (!isRecord(entry)) {
 99→      continue;
100→    }
101→    const provider = typeof entry.provider === "string" ? entry.provider.trim() : "";
102→    const method = typeof entry.method === "string" ? entry.method.trim() : "";
103→    const choiceId = typeof entry.choiceId === "string" ? entry.choiceId.trim() : "";
104→    if (!provider || !method || !choiceId) {
105→      continue;
106→    }
107→    const choiceLabel = typeof entry.choiceLabel === "string" ? entry.choiceLabel.trim() : "";
108→    const choiceHint = typeof entry.choiceHint === "string" ? entry.choiceHint.trim() : "";
109→    const groupId = typeof entry.groupId === "string" ? entry.groupId.trim() : "";
110→    const groupLabel = typeof entry.groupLabel === "string" ? entry.groupLabel.trim() : "";
111→    const groupHint = typeof entry.groupHint === "string" ? entry.groupHint.trim() : "";
112→    const optionKey = typeof entry.optionKey === "string" ? entry.optionKey.trim() : "";
113→    const cliFlag = typeof entry.cliFlag === "string" ? entry.cliFlag.trim() : "";
114→    const cliOption = typeof entry.cliOption === "string" ? entry.cliOption.trim() : "";
115→    const cliDescription =
116→      typeof entry.cliDescription === "string" ? entry.cliDescription.trim() : "";
117→    const onboardingScopes = normalizeStringList(entry.onboardingScopes).filter(
118→      (scope): scope is PluginManifestOnboardingScope =>
119→        scope === "text-inference" || scope === "image-generation",
120→    );
121→    normalized.push({
122→      provider,
123→      method,
124→      choiceId,
125→      ...(choiceLabel ? { choiceLabel } : {}),
126→      ...(choiceHint ? { choiceHint } : {}),
127→      ...(groupId ? { groupId } : {}),
128→      ...(groupLabel ? { groupLabel } : {}),
129→      ...(groupHint ? { groupHint } : {}),
130→      ...(optionKey ? { optionKey } : {}),
131→      ...(cliFlag ? { cliFlag } : {}),
132→      ...(cliOption ? { cliOption } : {}),
133→      ...(cliDescription ? { cliDescription } : {}),
134→      ...(onboardingScopes.length > 0 ? { onboardingScopes } : {}),
135→    });
136→  }
137→  return normalized.length > 0 ? normalized : undefined;
138→}
