140→export function resolvePluginManifestPath(rootDir: string): string {
141→  for (const filename of PLUGIN_MANIFEST_FILENAMES) {
142→    const candidate = path.join(rootDir, filename);
143→    if (fs.existsSync(candidate)) {
144→      return candidate;
145→    }
146→  }
147→  return path.join(rootDir, PLUGIN_MANIFEST_FILENAME);
148→}
149→
150→export function loadPluginManifest(
151→  rootDir: string,
152→  rejectHardlinks = true,
153→): PluginManifestLoadResult {
154→  const manifestPath = resolvePluginManifestPath(rootDir);
155→  const opened = openBoundaryFileSync({
156→    absolutePath: manifestPath,
157→    rootPath: rootDir,
158→    boundaryLabel: "plugin root",
159→    rejectHardlinks,
160→  });
161→  if (!opened.ok) {
162→    return matchBoundaryFileOpenFailure(opened, {
163→      path: () => ({
164→        ok: false,
165→        error: `plugin manifest not found: ${manifestPath}`,
166→        manifestPath,
167→      }),
168→      fallback: (failure) => ({
169→        ok: false,
170→        error: `unsafe plugin manifest path: ${manifestPath} (${failure.reason})`,
171→        manifestPath,
172→      }),
173→    });
174→  }
175→  let raw: unknown;
176→  try {
177→    raw = JSON.parse(fs.readFileSync(opened.fd, "utf-8")) as unknown;
178→  } catch (err) {
179→    return {
180→      ok: false,
181→      error: `failed to parse plugin manifest: ${String(err)}`,
182→      manifestPath,
183→    };
184→  } finally {
185→    fs.closeSync(opened.fd);
186→  }
187→  if (!isRecord(raw)) {
188→    return { ok: false, error: "plugin manifest must be an object", manifestPath };
189→  }
190→  const id = typeof raw.id === "string" ? raw.id.trim() : "";
191→  if (!id) {
192→    return { ok: false, error: "plugin manifest requires id", manifestPath };
193→  }
194→  const configSchema = isRecord(raw.configSchema) ? raw.configSchema : null;
195→  if (!configSchema) {
196→    return { ok: false, error: "plugin manifest requires configSchema", manifestPath };
197→  }
198→
199→  const kind = typeof raw.kind === "string" ? (raw.kind as PluginKind) : undefined;
200→  const enabledByDefault = raw.enabledByDefault === true;
201→  const name = typeof raw.name === "string" ? raw.name.trim() : undefined;
202→  const description = typeof raw.description === "string" ? raw.description.trim() : undefined;
203→  const version = typeof raw.version === "string" ? raw.version.trim() : undefined;
204→  const channels = normalizeStringList(raw.channels);
205→  const providers = normalizeStringList(raw.providers);
206→  const providerAuthEnvVars = normalizeStringListRecord(raw.providerAuthEnvVars);
207→  const providerAuthChoices = normalizeProviderAuthChoices(raw.providerAuthChoices);
208→  const skills = normalizeStringList(raw.skills);
209→
210→  let uiHints: Record<string, PluginConfigUiHint> | undefined;
211→  if (isRecord(raw.uiHints)) {
212→    uiHints = raw.uiHints as Record<string, PluginConfigUiHint>;
213→  }
214→
215→  return {
216→    ok: true,
217→    manifest: {
218→      id,
219→      configSchema,
220→      ...(enabledByDefault ? { enabledByDefault } : {}),
221→      kind,
222→      channels,
223→      providers,
224→      providerAuthEnvVars,
225→      providerAuthChoices,
226→      skills,
227→      name,
228→      description,
229→      version,
230→      uiHints,
231→    },
232→    manifestPath,
233→  };
234→}
