288→export type PackageExtensionResolution =
289→  | { status: "ok"; entries: string[] }
290→  | { status: "missing"; entries: [] }
291→  | { status: "empty"; entries: [] };
292→
293→export type ManifestKey = typeof MANIFEST_KEY;
294→
295→export type PackageManifest = {
296→  name?: string;
297→  version?: string;
298→  description?: string;
299→} & Partial<Record<ManifestKey, OpenClawPackageManifest>>;
300→
301→export function getPackageManifestMetadata(
302→  manifest: PackageManifest | undefined,
303→): OpenClawPackageManifest | undefined {
304→  if (!manifest) {
305→    return undefined;
306→  }
307→  return manifest[MANIFEST_KEY];
308→}
309→
310→export function resolvePackageExtensionEntries(
311→  manifest: PackageManifest | undefined,
312→): PackageExtensionResolution {
313→  const raw = getPackageManifestMetadata(manifest)?.extensions;
314→  if (!Array.isArray(raw)) {
315→    return { status: "missing", entries: [] };
316→  }
317→  const entries = raw
318→    .map((entry) => (typeof entry === "string" ? entry.trim() : ""))
319→    .filter(Boolean);
320→  if (entries.length === 0) {
321→    return { status: "empty", entries: [] };
322→  }
323→  return { status: "ok", entries };
324→}
