 231→const constrainLegacyPromptInjectionHook = (
 232→  handler: PluginHookHandlerMap["before_agent_start"],
 233→): PluginHookHandlerMap["before_agent_start"] => {
 234→  return (event, ctx) => {
 235→    const result = handler(event, ctx);
 236→    if (result && typeof result === "object" && "then" in result) {
 237→      return Promise.resolve(result).then((resolved) =>
 238→        stripPromptMutationFieldsFromLegacyHookResult(resolved),
 239→      );
 240→    }
 241→    return stripPromptMutationFieldsFromLegacyHookResult(result);
 242→  };
 243→};
