 245→export { createEmptyPluginRegistry } from "./registry-empty.js";
 246→
 247→export function createPluginRegistry(registryParams: PluginRegistryParams) {
 248→  const registry = createEmptyPluginRegistry();
 249→  const coreGatewayMethods = new Set(Object.keys(registryParams.coreGatewayHandlers ?? {}));
 250→
 251→  const pushDiagnostic = (diag: PluginDiagnostic) => {
 252→    registry.diagnostics.push(diag);
 253→  };
 254→
 255→  const registerTool = (
 256→    record: PluginRecord,
 257→    tool: AnyAgentTool | OpenClawPluginToolFactory,
 258→    opts?: { name?: string; names?: string[]; optional?: boolean },
 259→  ) => {
 260→    const names = opts?.names ?? (opts?.name ? [opts.name] : []);
 261→    const optional = opts?.optional === true;
 262→    const factory: OpenClawPluginToolFactory =
 263→      typeof tool === "function" ? tool : (_ctx: OpenClawPluginToolContext) => tool;
 264→
 265→    if (typeof tool !== "function") {
 266→      names.push(tool.name);
 267→    }
 268→
 269→    const normalized = names.map((name) => name.trim()).filter(Boolean);
 270→    if (normalized.length > 0) {
 271→      record.toolNames.push(...normalized);
 272→    }
 273→    registry.tools.push({
 274→      pluginId: record.id,
 275→      pluginName: record.name,
 276→      factory,
 277→      names: normalized,
 278→      optional,
 279→      source: record.source,
 280→      rootDir: record.rootDir,
 281→    });
 282→  };
 283→
 284→  const registerHook = (
 285→    record: PluginRecord,
 286→    events: string | string[],
 287→    handler: Parameters<typeof registerInternalHook>[1],
 288→    opts: OpenClawPluginHookOptions | undefined,
 289→    config: OpenClawPluginApi["config"],
 290→  ) => {
 291→    const eventList = Array.isArray(events) ? events : [events];
 292→    const normalizedEvents = eventList.map((event) => event.trim()).filter(Boolean);
 293→    const entry = opts?.entry ?? null;
 294→    const name = entry?.hook.name ?? opts?.name?.trim();
 295→    if (!name) {
 296→      pushDiagnostic({
 297→        level: "warn",
 298→        pluginId: record.id,
 299→        source: record.source,
 300→        message: "hook registration missing name",
 301→      });
 302→      return;
 303→    }
 304→    const existingHook = registry.hooks.find((entry) => entry.entry.hook.name === name);
 305→    if (existingHook) {
 306→      pushDiagnostic({
 307→        level: "error",
 308→        pluginId: record.id,
 309→        source: record.source,
 310→        message: `hook already registered: ${name} (${existingHook.pluginId})`,
 311→      });
 312→      return;
 313→    }
 314→
 315→    const description = entry?.hook.description ?? opts?.description ?? "";
 316→    const hookEntry: HookEntry = entry
 317→      ? {
 318→          ...entry,
 319→          hook: {
 320→            ...entry.hook,
 321→            name,
 322→            description,
 323→            source: "openclaw-plugin",
 324→            pluginId: record.id,
 325→          },
 326→          metadata: {
 327→            ...entry.metadata,
 328→            events: normalizedEvents,
 329→          },
 330→        }
 331→      : {
 332→          hook: {
 333→            name,
 334→            description,
 335→            source: "openclaw-plugin",
 336→            pluginId: record.id,
 337→            filePath: record.source,
 338→            baseDir: path.dirname(record.source),
 339→            handlerPath: record.source,
 340→          },
 341→          frontmatter: {},
 342→          metadata: { events: normalizedEvents },
 343→          invocation: { enabled: true },
 344→        };
 345→
 346→    record.hookNames.push(name);
 347→    registry.hooks.push({
 348→      pluginId: record.id,
 349→      entry: hookEntry,
 350→      events: normalizedEvents,
 351→      source: record.source,
 352→    });
 353→
 354→    const hookSystemEnabled = config?.hooks?.internal?.enabled === true;
 355→    if (!hookSystemEnabled || opts?.register === false) {
 356→      return;
 357→    }
 358→
 359→    for (const event of normalizedEvents) {
 360→      registerInternalHook(event, handler);
 361→    }
 362→  };
 363→
 364→  const registerGatewayMethod = (
 365→    record: PluginRecord,
 366→    method: string,
 367→    handler: GatewayRequestHandler,
 368→  ) => {
 369→    const trimmed = method.trim();
 370→    if (!trimmed) {
 371→      return;
 372→    }
 373→    if (coreGatewayMethods.has(trimmed) || registry.gatewayHandlers[trimmed]) {
 374→      pushDiagnostic({
 375→        level: "error",
 376→        pluginId: record.id,
 377→        source: record.source,
 378→        message: `gateway method already registered: ${trimmed}`,
 379→      });
 380→      return;
 381→    }
 382→    registry.gatewayHandlers[trimmed] = handler;
 383→    record.gatewayMethods.push(trimmed);
 384→  };
 385→
 386→  const describeHttpRouteOwner = (entry: PluginHttpRouteRegistration): string => {
 387→    const plugin = entry.pluginId?.trim() || "unknown-plugin";
 388→    const source = entry.source?.trim() || "unknown-source";
 389→    return `${plugin} (${source})`;
 390→  };
 391→
 392→  const registerHttpRoute = (record: PluginRecord, params: OpenClawPluginHttpRouteParams) => {
 393→    const normalizedPath = normalizePluginHttpPath(params.path);
 394→    if (!normalizedPath) {
 395→      pushDiagnostic({
 396→        level: "warn",
 397→        pluginId: record.id,
 398→        source: record.source,
 399→        message: "http route registration missing path",
 400→      });
 401→      return;
 402→    }
 403→    if (params.auth !== "gateway" && params.auth !== "plugin") {
 404→      pushDiagnostic({
 405→        level: "error",
 406→        pluginId: record.id,
 407→        source: record.source,
 408→        message: `http route registration missing or invalid auth: ${normalizedPath}`,
 409→      });
 410→      return;
 411→    }
 412→    const match = params.match ?? "exact";
 413→    const overlappingRoute = findOverlappingPluginHttpRoute(registry.httpRoutes, {
 414→      path: normalizedPath,
 415→      match,
 416→    });
 417→    if (overlappingRoute && overlappingRoute.auth !== params.auth) {
 418→      pushDiagnostic({
 419→        level: "error",
 420→        pluginId: record.id,
 421→        source: record.source,
 422→        message:
 423→          `http route overlap rejected: ${normalizedPath} (${match}, ${params.auth}) ` +
 424→          `overlaps ${overlappingRoute.path} (${overlappingRoute.match}, ${overlappingRoute.auth}) ` +
 425→          `owned by ${describeHttpRouteOwner(overlappingRoute)}`,
 426→      });
 427→      return;
 428→    }
 429→    const existingIndex = registry.httpRoutes.findIndex(
 430→      (entry) => entry.path === normalizedPath && entry.match === match,
 431→    );
 432→    if (existingIndex >= 0) {
 433→      const existing = registry.httpRoutes[existingIndex];
 434→      if (!existing) {
 435→        return;
 436→      }
 437→      if (!params.replaceExisting) {
 438→        pushDiagnostic({
 439→          level: "error",
 440→          pluginId: record.id,
 441→          source: record.source,
 442→          message: `http route already registered: ${normalizedPath} (${match}) by ${describeHttpRouteOwner(existing)}`,
 443→        });
 444→        return;
 445→      }
 446→      if (existing.pluginId && existing.pluginId !== record.id) {
 447→        pushDiagnostic({
 448→          level: "error",
 449→          pluginId: record.id,
 450→          source: record.source,
 451→          message: `http route replacement rejected: ${normalizedPath} (${match}) owned by ${describeHttpRouteOwner(existing)}`,
 452→        });
 453→        return;
 454→      }
 455→      registry.httpRoutes[existingIndex] = {
 456→        pluginId: record.id,
 457→        path: normalizedPath,
 458→        handler: params.handler,
 459→        auth: params.auth,
 460→        match,
 461→        source: record.source,
 462→      };
 463→      return;
 464→    }
 465→    record.httpRoutes += 1;
 466→    registry.httpRoutes.push({
 467→      pluginId: record.id,
 468→      path: normalizedPath,
 469→      handler: params.handler,
 470→      auth: params.auth,
 471→      match,
 472→      source: record.source,
 473→    });
 474→  };
 475→
 476→  const registerChannel = (
 477→    record: PluginRecord,
 478→    registration: OpenClawPluginChannelRegistration | ChannelPlugin,
 479→    mode: PluginRegistrationMode = "full",
 480→  ) => {
 481→    const normalized =
 482→      typeof (registration as OpenClawPluginChannelRegistration).plugin === "object"
 483→        ? (registration as OpenClawPluginChannelRegistration)
 484→        : { plugin: registration as ChannelPlugin };
 485→    const plugin = normalized.plugin;
 486→    const id = typeof plugin?.id === "string" ? plugin.id.trim() : String(plugin?.id ?? "").trim();
 487→    if (!id) {
 488→      pushDiagnostic({
 489→        level: "error",
 490→        pluginId: record.id,
 491→        source: record.source,
 492→        message: "channel registration missing id",
 493→      });
 494→      return;
 495→    }
 496→    const existingRuntime = registry.channels.find((entry) => entry.plugin.id === id);
 497→    if (mode !== "setup-only" && existingRuntime) {
 498→      pushDiagnostic({
 499→        level: "error",
 500→        pluginId: record.id,
 501→        source: record.source,
 502→        message: `channel already registered: ${id} (${existingRuntime.pluginId})`,
 503→      });
 504→      return;
 505→    }
 506→    const existingSetup = registry.channelSetups.find((entry) => entry.plugin.id === id);
 507→    if (existingSetup) {
 508→      pushDiagnostic({
 509→        level: "error",
 510→        pluginId: record.id,
 511→        source: record.source,
 512→        message: `channel setup already registered: ${id} (${existingSetup.pluginId})`,
 513→      });
 514→      return;
 515→    }
 516→    record.channelIds.push(id);
 517→    registry.channelSetups.push({
 518→      pluginId: record.id,
 519→      pluginName: record.name,
 520→      plugin,
 521→      source: record.source,
 522→      enabled: record.enabled,
 523→      rootDir: record.rootDir,
 524→    });
 525→    if (mode === "setup-only") {
 526→      return;
 527→    }
 528→    registry.channels.push({
 529→      pluginId: record.id,
 530→      pluginName: record.name,
 531→      plugin,
 532→      source: record.source,
 533→      rootDir: record.rootDir,
 534→    });
 535→  };
 536→
 537→  const registerProvider = (record: PluginRecord, provider: ProviderPlugin) => {
 538→    const normalizedProvider = normalizeRegisteredProvider({
 539→      pluginId: record.id,
 540→      source: record.source,
 541→      provider,
 542→      pushDiagnostic,
 543→    });
 544→    if (!normalizedProvider) {
 545→      return;
 546→    }
 547→    const id = normalizedProvider.id;
 548→    const existing = registry.providers.find((entry) => entry.provider.id === id);
 549→    if (existing) {
 550→      pushDiagnostic({
 551→        level: "error",
 552→        pluginId: record.id,
 553→        source: record.source,
 554→        message: `provider already registered: ${id} (${existing.pluginId})`,
 555→      });
 556→      return;
 557→    }
 558→    record.providerIds.push(id);
 559→    registry.providers.push({
 560→      pluginId: record.id,
 561→      pluginName: record.name,
 562→      provider: normalizedProvider,
 563→      source: record.source,
 564→      rootDir: record.rootDir,
 565→    });
 566→  };
 567→
 568→  const registerUniqueProviderLike = <
 569→    T extends { id: string },
 570→    R extends PluginOwnedProviderRegistration<T>,
 571→  >(params: {
 572→    record: PluginRecord;
 573→    provider: T;
 574→    kindLabel: string;
 575→    registrations: R[];
 576→    ownedIds: string[];
 577→  }) => {
 578→    const id = params.provider.id.trim();
 579→    const { record, kindLabel } = params;
 580→    const missingLabel = `${kindLabel} registration missing id`;
 581→    const duplicateLabel = `${kindLabel} already registered: ${id}`;
 582→    if (!id) {
 583→      pushDiagnostic({
 584→        level: "error",
 585→        pluginId: record.id,
 586→        source: record.source,
 587→        message: missingLabel,
 588→      });
 589→      return;
 590→    }
 591→    const existing = params.registrations.find((entry) => entry.provider.id === id);
 592→    if (existing) {
 593→      pushDiagnostic({
 594→        level: "error",
 595→        pluginId: record.id,
 596→        source: record.source,
 597→        message: `${duplicateLabel} (${existing.pluginId})`,
 598→      });
 599→      return;
 600→    }
 601→    params.ownedIds.push(id);
 602→    params.registrations.push({
 603→      pluginId: record.id,
 604→      pluginName: record.name,
 605→      provider: params.provider,
 606→      source: record.source,
 607→      rootDir: record.rootDir,
 608→    } as R);
 609→  };
 610→
 611→  const registerSpeechProvider = (record: PluginRecord, provider: SpeechProviderPlugin) => {
 612→    registerUniqueProviderLike({
 613→      record,
 614→      provider,
 615→      kindLabel: "speech provider",
 616→      registrations: registry.speechProviders,
 617→      ownedIds: record.speechProviderIds,
 618→    });
 619→  };
 620→
 621→  const registerMediaUnderstandingProvider = (
 622→    record: PluginRecord,
 623→    provider: MediaUnderstandingProviderPlugin,
 624→  ) => {
 625→    registerUniqueProviderLike({
 626→      record,
 627→      provider,
 628→      kindLabel: "media provider",
 629→      registrations: registry.mediaUnderstandingProviders,
 630→      ownedIds: record.mediaUnderstandingProviderIds,
 631→    });
 632→  };
 633→
 634→  const registerImageGenerationProvider = (
 635→    record: PluginRecord,
 636→    provider: ImageGenerationProviderPlugin,
 637→  ) => {
 638→    registerUniqueProviderLike({
 639→      record,
 640→      provider,
 641→      kindLabel: "image-generation provider",
 642→      registrations: registry.imageGenerationProviders,
 643→      ownedIds: record.imageGenerationProviderIds,
 644→    });
 645→  };
 646→
 647→  const registerWebSearchProvider = (record: PluginRecord, provider: WebSearchProviderPlugin) => {
 648→    registerUniqueProviderLike({
 649→      record,
 650→      provider,
 651→      kindLabel: "web search provider",
 652→      registrations: registry.webSearchProviders,
 653→      ownedIds: record.webSearchProviderIds,
 654→    });
 655→  };
 656→
 657→  const registerCli = (
 658→    record: PluginRecord,
 659→    registrar: OpenClawPluginCliRegistrar,
 660→    opts?: { commands?: string[] },
 661→  ) => {
 662→    const commands = (opts?.commands ?? []).map((cmd) => cmd.trim()).filter(Boolean);
 663→    if (commands.length === 0) {
 664→      pushDiagnostic({
 665→        level: "error",
 666→        pluginId: record.id,
 667→        source: record.source,
 668→        message: "cli registration missing explicit commands metadata",
 669→      });
 670→      return;
 671→    }
 672→    const existing = registry.cliRegistrars.find((entry) =>
 673→      entry.commands.some((command) => commands.includes(command)),
 674→    );
 675→    if (existing) {
 676→      const overlap = commands.find((command) => existing.commands.includes(command));
 677→      pushDiagnostic({
 678→        level: "error",
 679→        pluginId: record.id,
 680→        source: record.source,
 681→        message: `cli command already registered: ${overlap ?? commands[0]} (${existing.pluginId})`,
 682→      });
 683→      return;
 684→    }
 685→    record.cliCommands.push(...commands);
 686→    registry.cliRegistrars.push({
 687→      pluginId: record.id,
 688→      pluginName: record.name,
 689→      register: registrar,
 690→      commands,
 691→      source: record.source,
 692→      rootDir: record.rootDir,
 693→    });
 694→  };
 695→
 696→  const registerService = (record: PluginRecord, service: OpenClawPluginService) => {
 697→    const id = service.id.trim();
 698→    if (!id) {
 699→      return;
 700→    }
 701→    const existing = registry.services.find((entry) => entry.service.id === id);
 702→    if (existing) {
 703→      pushDiagnostic({
 704→        level: "error",
 705→        pluginId: record.id,
 706→        source: record.source,
 707→        message: `service already registered: ${id} (${existing.pluginId})`,
 708→      });
 709→      return;
 710→    }
 711→    record.services.push(id);
 712→    registry.services.push({
 713→      pluginId: record.id,
 714→      pluginName: record.name,
 715→      service,
 716→      source: record.source,
 717→      rootDir: record.rootDir,
 718→    });
 719→  };
 720→
 721→  const registerCommand = (record: PluginRecord, command: OpenClawPluginCommandDefinition) => {
 722→    const name = command.name.trim();
 723→    if (!name) {
 724→      pushDiagnostic({
 725→        level: "error",
 726→        pluginId: record.id,
 727→        source: record.source,
 728→        message: "command registration missing name",
 729→      });
 730→      return;
 731→    }
 732→
 733→    // For snapshot (non-activating) loads, record the command locally without touching the
 734→    // global plugin command registry so running gateway commands stay intact.
 735→    // We still validate the command definition so diagnostics match the real activation path.
 736→    // NOTE: cross-plugin duplicate command detection is intentionally skipped here because
 737→    // snapshot registries are isolated and never write to the global command table. Conflicts
 738→    // will surface when the plugin is loaded via the normal activation path at gateway startup.
 739→    if (registryParams.suppressGlobalCommands) {
 740→      const validationError = validatePluginCommandDefinition(command);
 741→      if (validationError) {
 742→        pushDiagnostic({
 743→          level: "error",
 744→          pluginId: record.id,
 745→          source: record.source,
 746→          message: `command registration failed: ${validationError}`,
 747→        });
 748→        return;
 749→      }
 750→    } else {
 751→      const result = registerPluginCommand(record.id, command, {
 752→        pluginName: record.name,
 753→        pluginRoot: record.rootDir,
 754→      });
 755→      if (!result.ok) {
 756→        pushDiagnostic({
 757→          level: "error",
 758→          pluginId: record.id,
 759→          source: record.source,
 760→          message: `command registration failed: ${result.error}`,
 761→        });
 762→        return;
 763→      }
 764→    }
 765→
 766→    record.commands.push(name);
 767→    registry.commands.push({
 768→      pluginId: record.id,
 769→      pluginName: record.name,
 770→      command,
 771→      source: record.source,
 772→      rootDir: record.rootDir,
 773→    });
 774→  };
 775→
 776→  const registerTypedHook = <K extends PluginHookName>(
 777→    record: PluginRecord,
 778→    hookName: K,
 779→    handler: PluginHookHandlerMap[K],
 780→    opts?: { priority?: number },
 781→    policy?: PluginTypedHookPolicy,
 782→  ) => {
 783→    if (!isPluginHookName(hookName)) {
 784→      pushDiagnostic({
 785→        level: "warn",
 786→        pluginId: record.id,
 787→        source: record.source,
 788→        message: `unknown typed hook "${String(hookName)}" ignored`,
 789→      });
 790→      return;
 791→    }
 792→    let effectiveHandler = handler;
 793→    if (policy?.allowPromptInjection === false && isPromptInjectionHookName(hookName)) {
 794→      if (hookName === "before_prompt_build") {
 795→        pushDiagnostic({
 796→          level: "warn",
 797→          pluginId: record.id,
 798→          source: record.source,
 799→          message: `typed hook "${hookName}" blocked by plugins.entries.${record.id}.hooks.allowPromptInjection=false`,
 800→        });
 801→        return;
 802→      }
 803→      if (hookName === "before_agent_start") {
 804→        pushDiagnostic({
 805→          level: "warn",
 806→          pluginId: record.id,
 807→          source: record.source,
 808→          message: `typed hook "${hookName}" prompt fields constrained by plugins.entries.${record.id}.hooks.allowPromptInjection=false`,
 809→        });
 810→        effectiveHandler = constrainLegacyPromptInjectionHook(
 811→          handler as PluginHookHandlerMap["before_agent_start"],
 812→        ) as PluginHookHandlerMap[K];
 813→      }
 814→    }
 815→    record.hookCount += 1;
 816→    registry.typedHooks.push({
 817→      pluginId: record.id,
 818→      hookName,
 819→      handler: effectiveHandler,
 820→      priority: opts?.priority,
 821→      source: record.source,
 822→    } as TypedPluginHookRegistration);
 823→  };
 824→
 825→  const registerConversationBindingResolvedHandler = (
 826→    record: PluginRecord,
 827→    handler: (event: PluginConversationBindingResolvedEvent) => void | Promise<void>,
 828→  ) => {
 829→    registry.conversationBindingResolvedHandlers.push({
 830→      pluginId: record.id,
 831→      pluginName: record.name,
 832→      pluginRoot: record.rootDir,
 833→      handler,
 834→      source: record.source,
 835→      rootDir: record.rootDir,
 836→    });
 837→  };
 838→
 839→  const normalizeLogger = (logger: PluginLogger): PluginLogger => ({
 840→    info: logger.info,
 841→    warn: logger.warn,
 842→    error: logger.error,
 843→    debug: logger.debug,
 844→  });
 845→
 846→  const pluginRuntimeById = new Map<string, PluginRuntime>();
 847→
 848→  const resolvePluginRuntime = (pluginId: string): PluginRuntime => {
 849→    const cached = pluginRuntimeById.get(pluginId);
 850→    if (cached) {
 851→      return cached;
 852→    }
 853→    const runtime = new Proxy(registryParams.runtime, {
 854→      get(target, prop, receiver) {
 855→        if (prop !== "subagent") {
 856→          return Reflect.get(target, prop, receiver);
 857→        }
 858→        const subagent = Reflect.get(target, prop, receiver);
 859→        return {
 860→          run: (params) => withPluginRuntimePluginIdScope(pluginId, () => subagent.run(params)),
 861→          waitForRun: (params) =>
 862→            withPluginRuntimePluginIdScope(pluginId, () => subagent.waitForRun(params)),
 863→          getSessionMessages: (params) =>
 864→            withPluginRuntimePluginIdScope(pluginId, () => subagent.getSessionMessages(params)),
 865→          getSession: (params) =>
 866→            withPluginRuntimePluginIdScope(pluginId, () => subagent.getSession(params)),
 867→          deleteSession: (params) =>
 868→            withPluginRuntimePluginIdScope(pluginId, () => subagent.deleteSession(params)),
 869→        } satisfies PluginRuntime["subagent"];
 870→      },
 871→    });
 872→    pluginRuntimeById.set(pluginId, runtime);
 873→    return runtime;
 874→  };
 875→
 876→  const createApi = (
 877→    record: PluginRecord,
 878→    params: {
 879→      config: OpenClawPluginApi["config"];
 880→      pluginConfig?: Record<string, unknown>;
 881→      hookPolicy?: PluginTypedHookPolicy;
 882→      registrationMode?: PluginRegistrationMode;
 883→    },
 884→  ): OpenClawPluginApi => {
 885→    const registrationMode = params.registrationMode ?? "full";
 886→    return {
 887→      id: record.id,
 888→      name: record.name,
 889→      version: record.version,
 890→      description: record.description,
 891→      source: record.source,
 892→      rootDir: record.rootDir,
 893→      registrationMode,
 894→      config: params.config,
 895→      pluginConfig: params.pluginConfig,
 896→      runtime: resolvePluginRuntime(record.id),
 897→      logger: normalizeLogger(registryParams.logger),
 898→      registerTool:
 899→        registrationMode === "full" ? (tool, opts) => registerTool(record, tool, opts) : () => {},
 900→      registerHook:
 901→        registrationMode === "full"
 902→          ? (events, handler, opts) => registerHook(record, events, handler, opts, params.config)
 903→          : () => {},
 904→      registerHttpRoute:
 905→        registrationMode === "full" ? (params) => registerHttpRoute(record, params) : () => {},
 906→      registerChannel: (registration) => registerChannel(record, registration, registrationMode),
 907→      registerProvider:
 908→        registrationMode === "full" ? (provider) => registerProvider(record, provider) : () => {},
 909→      registerSpeechProvider:
 910→        registrationMode === "full"
 911→          ? (provider) => registerSpeechProvider(record, provider)
 912→          : () => {},
 913→      registerMediaUnderstandingProvider:
 914→        registrationMode === "full"
 915→          ? (provider) => registerMediaUnderstandingProvider(record, provider)
 916→          : () => {},
 917→      registerImageGenerationProvider:
 918→        registrationMode === "full"
 919→          ? (provider) => registerImageGenerationProvider(record, provider)
 920→          : () => {},
 921→      registerWebSearchProvider:
 922→        registrationMode === "full"
 923→          ? (provider) => registerWebSearchProvider(record, provider)
 924→          : () => {},
 925→      registerGatewayMethod:
 926→        registrationMode === "full"
 927→          ? (method, handler) => registerGatewayMethod(record, method, handler)
 928→          : () => {},
 929→      registerCli:
 930→        registrationMode === "full"
 931→          ? (registrar, opts) => registerCli(record, registrar, opts)
 932→          : () => {},
 933→      registerService:
 934→        registrationMode === "full" ? (service) => registerService(record, service) : () => {},
 935→      registerInteractiveHandler:
 936→        registrationMode === "full"
 937→          ? (registration) => {
 938→              const result = registerPluginInteractiveHandler(record.id, registration, {
 939→                pluginName: record.name,
 940→                pluginRoot: record.rootDir,
 941→              });
 942→              if (!result.ok) {
 943→                pushDiagnostic({
 944→                  level: "warn",
 945→                  pluginId: record.id,
 946→                  source: record.source,
 947→                  message: result.error ?? "interactive handler registration failed",
 948→                });
 949→              }
 950→            }
 951→          : () => {},
 952→      onConversationBindingResolved:
 953→        registrationMode === "full"
 954→          ? (handler) => registerConversationBindingResolvedHandler(record, handler)
 955→          : () => {},
 956→      registerCommand:
 957→        registrationMode === "full" ? (command) => registerCommand(record, command) : () => {},
 958→      registerContextEngine: (id, factory) => {
 959→        if (registrationMode !== "full") {
 960→          return;
 961→        }
 962→        if (id === defaultSlotIdForKey("contextEngine")) {
 963→          pushDiagnostic({
 964→            level: "error",
 965→            pluginId: record.id,
 966→            source: record.source,
 967→            message: `context engine id reserved by core: ${id}`,
 968→          });
 969→          return;
 970→        }
 971→        const result = registerContextEngineForOwner(id, factory, `plugin:${record.id}`, {
 972→          allowSameOwnerRefresh: true,
 973→        });
 974→        if (!result.ok) {
 975→          pushDiagnostic({
 976→            level: "error",
 977→            pluginId: record.id,
 978→            source: record.source,
 979→            message: `context engine already registered: ${id} (${result.existingOwner})`,
 980→          });
 981→        }
 982→      },
 983→      registerMemoryPromptSection: (builder) => {
 984→        if (registrationMode !== "full") {
 985→          return;
 986→        }
 987→        if (record.kind !== "memory") {
 988→          pushDiagnostic({
 989→            level: "error",
 990→            pluginId: record.id,
 991→            source: record.source,
 992→            message: "only memory plugins can register a memory prompt section",
 993→          });
 994→          return;
 995→        }
 996→        registerMemoryPromptSection(builder);
 997→      },
 998→      resolvePath: (input: string) => resolveUserPath(input),
 999→      on: (hookName, handler, opts) =>
1000→        registrationMode === "full"
1001→          ? registerTypedHook(record, hookName, handler, opts, params.hookPolicy)
1002→          : undefined,
1003→    };
1004→  };
1005→
1006→  return {
1007→    registry,
1008→    createApi,
1009→    pushDiagnostic,
1010→    registerTool,
1011→    registerChannel,
1012→    registerProvider,
1013→    registerSpeechProvider,
1014→    registerMediaUnderstandingProvider,
1015→    registerImageGenerationProvider,
1016→    registerWebSearchProvider,
1017→    registerGatewayMethod,
1018→    registerCli,
1019→    registerService,
1020→    registerCommand,
1021→    registerHook,
1022→    registerTypedHook,
1023→  };
1024→}
