 4→export type OAuthPrompt = { message: string; placeholder?: string };
 5→
 6→const validateRequiredInput = (value: string) => (value.trim().length > 0 ? undefined : "Required");
 7→
 8→export function createVpsAwareOAuthHandlers(params: {
 9→  isRemote: boolean;
10→  prompter: WizardPrompter;
11→  runtime: RuntimeEnv;
12→  spin: ReturnType<WizardPrompter["progress"]>;
13→  openUrl: (url: string) => Promise<unknown>;
14→  localBrowserMessage: string;
15→  manualPromptMessage?: string;
16→}): {
17→  onAuth: (event: { url: string }) => Promise<void>;
18→  onPrompt: (prompt: OAuthPrompt) => Promise<string>;
19→} {
20→  const manualPromptMessage = params.manualPromptMessage ?? "Paste the redirect URL";
21→  let manualCodePromise: Promise<string> | undefined;
22→
23→  return {
24→    onAuth: async ({ url }) => {
25→      if (params.isRemote) {
26→        params.spin.stop("OAuth URL ready");
27→        params.runtime.log(`\nOpen this URL in your LOCAL browser:\n\n${url}\n`);
28→        manualCodePromise = params.prompter
29→          .text({
30→            message: manualPromptMessage,
31→            validate: validateRequiredInput,
32→          })
33→          .then((value) => String(value));
34→        return;
35→      }
36→
37→      params.spin.update(params.localBrowserMessage);
38→      await params.openUrl(url);
39→      params.runtime.log(`Open: ${url}`);
40→    },
41→    onPrompt: async (prompt) => {
42→      if (manualCodePromise) {
43→        return manualCodePromise;
44→      }
45→      const code = await params.prompter.text({
46→        message: prompt.message,
47→        placeholder: prompt.placeholder,
48→        validate: validateRequiredInput,
49→      });
50→      return String(code);
51→    },
52→  };
53→}
