 1→import { clearCredentialsCache, extractGeminiCliCredentials } from "./oauth.credentials.js";
 2→import {
 3→  buildAuthUrl,
 4→  generatePkce,
 5→  parseCallbackInput,
 6→  shouldUseManualOAuthFlow,
 7→  waitForLocalCallback,
 8→} from "./oauth.flow.js";
 9→import type { GeminiCliOAuthContext, GeminiCliOAuthCredentials } from "./oauth.shared.js";
10→import { exchangeCodeForTokens } from "./oauth.token.js";
11→
12→export { clearCredentialsCache, extractGeminiCliCredentials };
13→export type { GeminiCliOAuthContext, GeminiCliOAuthCredentials };
14→
15→export async function loginGeminiCliOAuth(
16→  ctx: GeminiCliOAuthContext,
17→): Promise<GeminiCliOAuthCredentials> {
18→  const needsManual = shouldUseManualOAuthFlow(ctx.isRemote);
19→  await ctx.note(
20→    needsManual
21→      ? [
22→          "You are running in a remote/VPS environment.",
23→          "A URL will be shown for you to open in your LOCAL browser.",
24→          "After signing in, copy the redirect URL and paste it back here.",
25→        ].join("\n")
26→      : [
27→          "Browser will open for Google authentication.",
28→          "Sign in with your Google account for Gemini CLI access.",
29→          "The callback will be captured automatically on localhost:8085.",
30→        ].join("\n"),
31→    "Gemini CLI OAuth",
32→  );
33→
34→  const { verifier, challenge } = generatePkce();
35→  const authUrl = buildAuthUrl(challenge, verifier);
36→
37→  if (needsManual) {
38→    ctx.progress.update("OAuth URL ready");
39→    ctx.log(`\nOpen this URL in your LOCAL browser:\n\n${authUrl}\n`);
40→    ctx.progress.update("Waiting for you to paste the callback URL...");
41→    const callbackInput = await ctx.prompt("Paste the redirect URL here: ");
42→    const parsed = parseCallbackInput(callbackInput, verifier);
43→    if ("error" in parsed) {
44→      throw new Error(parsed.error);
45→    }
46→    if (parsed.state !== verifier) {
47→      throw new Error("OAuth state mismatch - please try again");
48→    }
49→    ctx.progress.update("Exchanging authorization code for tokens...");
50→    return exchangeCodeForTokens(parsed.code, verifier);
51→  }
52→
53→  ctx.progress.update("Complete sign-in in browser...");
54→  try {
55→    await ctx.openUrl(authUrl);
56→  } catch {
57→    ctx.log(`\nOpen this URL in your browser:\n\n${authUrl}\n`);
58→  }
59→
60→  try {
61→    const { code } = await waitForLocalCallback({
62→      expectedState: verifier,
63→      timeoutMs: 5 * 60 * 1000,
64→      onProgress: (msg) => ctx.progress.update(msg),
65→    });
66→    ctx.progress.update("Exchanging authorization code for tokens...");
67→    return await exchangeCodeForTokens(code, verifier);
68→  } catch (err) {
69→    if (
70→      err instanceof Error &&
71→      (err.message.includes("EADDRINUSE") ||
72→        err.message.includes("port") ||
73→        err.message.includes("listen"))
74→    ) {
75→      ctx.progress.update("Local callback server failed. Switching to manual mode...");
76→      ctx.log(`\nOpen this URL in your LOCAL browser:\n\n${authUrl}\n`);
77→      const callbackInput = await ctx.prompt("Paste the redirect URL here: ");
78→      const parsed = parseCallbackInput(callbackInput, verifier);
79→      if ("error" in parsed) {
80→        throw new Error(parsed.error, { cause: err });
81→      }
82→      if (parsed.state !== verifier) {
83→        throw new Error("OAuth state mismatch - please try again", { cause: err });
84→      }
85→      ctx.progress.update("Exchanging authorization code for tokens...");
86→      return exchangeCodeForTokens(parsed.code, verifier);
87→    }
88→    throw err;
89→  }
90→}
