 64→function resolveDiscoveryCacheMs(env: NodeJS.ProcessEnv): number {
 65→  const raw = env.OPENCLAW_PLUGIN_DISCOVERY_CACHE_MS?.trim();
 66→  if (raw === "" || raw === "0") {
 67→    return 0;
 68→  }
 69→  if (!raw) {
 70→    return DEFAULT_DISCOVERY_CACHE_MS;
 71→  }
 72→  const parsed = Number.parseInt(raw, 10);
 73→  if (!Number.isFinite(parsed)) {
 74→    return DEFAULT_DISCOVERY_CACHE_MS;
 75→  }
 76→  return Math.max(0, parsed);
 77→}
