 79→function shouldUseDiscoveryCache(env: NodeJS.ProcessEnv): boolean {
 80→  const disabled = env.OPENCLAW_DISABLE_PLUGIN_DISCOVERY_CACHE?.trim();
 81→  if (disabled) {
 82→    return false;
 83→  }
 84→  return resolveDiscoveryCacheMs(env) > 0;
 85→}
