 35→export function resolveBundledProviderCompatPluginIds(params: {
 36→  config?: PluginLoadOptions["config"];
 37→  workspaceDir?: string;
 38→  env?: PluginLoadOptions["env"];
 39→  onlyPluginIds?: string[];
 40→}): string[] {
 41→  const onlyPluginIdSet = params.onlyPluginIds ? new Set(params.onlyPluginIds) : null;
 42→  const registry = loadPluginManifestRegistry({
 43→    config: params.config,
 44→    workspaceDir: params.workspaceDir,
 45→    env: params.env,
 46→  });
 47→  return registry.plugins
 48→    .filter(
 49→      (plugin) =>
 50→        plugin.origin === "bundled" &&
 51→        plugin.providers.length > 0 &&
 52→        (!onlyPluginIdSet || onlyPluginIdSet.has(plugin.id)),
 53→    )
 54→    .map((plugin) => plugin.id)
 55→    .toSorted((left, right) => left.localeCompare(right));
 56→}
