 12→type ProviderApiKeyAuthMethodOptions = {
 13→  providerId: string;
 14→  methodId: string;
 15→  label: string;
 16→  hint?: string;
 17→  wizard?: ProviderPluginWizardSetup;
 18→  optionKey: string;
 19→  flagName: `--${string}`;
 20→  envVar: string;
 21→  promptMessage: string;
 22→  profileId?: string;
 23→  profileIds?: string[];
 24→  allowProfile?: boolean;
 25→  defaultModel?: string;
 26→  expectedProviders?: string[];
 27→  metadata?: Record<string, string>;
 28→  noteMessage?: string;
 29→  noteTitle?: string;
 30→  applyConfig?: (cfg: OpenClawConfig) => OpenClawConfig;
 31→};
 32→
 33→const loadProviderApiKeyAuthRuntime = createLazyRuntimeSurface(
 34→  () => import("./provider-api-key-auth.runtime.js"),
 35→  ({ providerApiKeyAuthRuntime }) => providerApiKeyAuthRuntime,
 36→);
 37→
 38→function resolveStringOption(opts: Record<string, unknown> | undefined, optionKey: string) {
 39→  return normalizeOptionalSecretInput(opts?.[optionKey]);
 40→}
 41→
 42→function resolveProfileId(params: { providerId: string; profileId?: string }) {
 43→  return params.profileId?.trim() || `${params.providerId}:default`;
 44→}
 45→
 46→function resolveProfileIds(params: {
 47→  providerId: string;
 48→  profileId?: string;
 49→  profileIds?: string[];
 50→}) {
 51→  const explicit = Array.from(
 52→    new Set((params.profileIds ?? []).map((value) => value.trim()).filter(Boolean)),
 53→  );
 54→  if (explicit.length > 0) {
 55→    return explicit;
 56→  }
 57→  return [resolveProfileId(params)];
 58→}
 59→
 60→async function applyApiKeyConfig(params: {
 61→  ctx: ProviderAuthMethodNonInteractiveContext;
 62→  providerId: string;
 63→  profileIds: string[];
 64→  defaultModel?: string;
 65→  applyConfig?: (cfg: OpenClawConfig) => OpenClawConfig;
 66→}) {
 67→  const { applyAuthProfileConfig, applyPrimaryModel } = await loadProviderApiKeyAuthRuntime();
 68→  let next = params.ctx.config;
 69→  for (const profileId of params.profileIds) {
 70→    next = applyAuthProfileConfig(next, {
 71→      profileId,
 72→      provider: profileId.split(":", 1)[0]?.trim() || params.providerId,
 73→      mode: "api_key",
 74→    });
 75→  }
 76→  if (params.applyConfig) {
 77→    next = params.applyConfig(next);
 78→  }
 79→  return params.defaultModel ? applyPrimaryModel(next, params.defaultModel) : next;
 80→}
 81→
 82→export function createProviderApiKeyAuthMethod(
 83→  params: ProviderApiKeyAuthMethodOptions,
 84→): ProviderAuthMethod {
 85→  return {
 86→    id: params.methodId,
 87→    label: params.label,
 88→    hint: params.hint,
 89→    kind: "api_key",
 90→    wizard: params.wizard,
 91→    run: async (ctx) => {
 92→      const opts = ctx.opts as Record<string, unknown> | undefined;
 93→      const flagValue = resolveStringOption(opts, params.optionKey);
 94→      let capturedSecretInput: SecretInput | undefined;
 95→      let capturedCredential = false;
 96→      let capturedMode: "plaintext" | "ref" | undefined;
 97→      const {
 98→        buildApiKeyCredential,
 99→        ensureApiKeyFromOptionEnvOrPrompt,
100→        normalizeApiKeyInput,
101→        validateApiKeyInput,
102→      } = await loadProviderApiKeyAuthRuntime();
103→
104→      await ensureApiKeyFromOptionEnvOrPrompt({
105→        token: flagValue ?? normalizeOptionalSecretInput(ctx.opts?.token),
106→        tokenProvider: flagValue
107→          ? params.providerId
108→          : normalizeOptionalSecretInput(ctx.opts?.tokenProvider),
109→        secretInputMode:
110→          ctx.allowSecretRefPrompt === false
111→            ? (ctx.secretInputMode ?? "plaintext")
112→            : ctx.secretInputMode,
113→        config: ctx.config,
114→        expectedProviders: params.expectedProviders ?? [params.providerId],
115→        provider: params.providerId,
116→        envLabel: params.envVar,
117→        promptMessage: params.promptMessage,
118→        normalize: normalizeApiKeyInput,
119→        validate: validateApiKeyInput,
120→        prompter: ctx.prompter,
121→        noteMessage: params.noteMessage,
122→        noteTitle: params.noteTitle,
123→        setCredential: async (apiKey, mode) => {
124→          capturedSecretInput = apiKey;
125→          capturedCredential = true;
126→          capturedMode = mode;
127→        },
128→      });
129→
130→      if (!capturedCredential) {
131→        throw new Error(`Missing API key input for provider "${params.providerId}".`);
132→      }
133→      const credentialInput = capturedSecretInput ?? "";
134→      const profileIds = resolveProfileIds(params);
135→
136→      return {
137→        profiles: profileIds.map((profileId) => ({
138→          profileId,
139→          credential: buildApiKeyCredential(
140→            profileId.split(":", 1)[0]?.trim() || params.providerId,
141→            credentialInput,
142→            params.metadata,
143→            capturedMode ? { secretInputMode: capturedMode } : undefined,
144→          ),
145→        })),
146→        ...(params.applyConfig ? { configPatch: params.applyConfig(ctx.config) } : {}),
147→        ...(params.defaultModel ? { defaultModel: params.defaultModel } : {}),
148→      };
149→    },
150→    runNonInteractive: async (ctx) => {
151→      const opts = ctx.opts as Record<string, unknown> | undefined;
152→      const resolved = await ctx.resolveApiKey({
153→        provider: params.providerId,
154→        flagValue: resolveStringOption(opts, params.optionKey),
155→        flagName: params.flagName,
156→        envVar: params.envVar,
157→        ...(params.allowProfile === false ? { allowProfile: false } : {}),
158→      });
159→      if (!resolved) {
160→        return null;
161→      }
162→
163→      const profileIds = resolveProfileIds(params);
164→      if (resolved.source !== "profile") {
165→        for (const profileId of profileIds) {
166→          const credential = ctx.toApiKeyCredential({
167→            provider: profileId.split(":", 1)[0]?.trim() || params.providerId,
168→            resolved,
169→            ...(params.metadata ? { metadata: params.metadata } : {}),
170→          });
171→          if (!credential) {
172→            return null;
173→          }
174→          upsertAuthProfile({
175→            profileId,
176→            credential,
177→            agentDir: ctx.agentDir,
178→          });
179→        }
180→      }
181→
182→      return await applyApiKeyConfig({
183→        ctx,
184→        providerId: params.providerId,
185→        profileIds,
186→        defaultModel: params.defaultModel,
187→        applyConfig: params.applyConfig,
188→      });
189→    },
190→  };
191→}
