48→function restoreConfiguredPrimaryModel(
49→  nextConfig: OpenClawConfig,
50→  originalConfig: OpenClawConfig,
51→): OpenClawConfig {
52→  const originalModel = originalConfig.agents?.defaults?.model;
53→  const nextAgents = nextConfig.agents;
54→  const nextDefaults = nextAgents?.defaults;
55→  if (!nextDefaults) {
56→    return nextConfig;
57→  }
58→  if (originalModel !== undefined) {
59→    return {
60→      ...nextConfig,
61→      agents: {
62→        ...nextAgents,
63→        defaults: {
64→          ...nextDefaults,
65→          model: originalModel,
66→        },
67→      },
68→    };
69→  }
70→  const { model: _model, ...restDefaults } = nextDefaults;
71→  return {
72→    ...nextConfig,
73→    agents: {
74→      ...nextAgents,
75→      defaults: restDefaults,
76→    },
77→  };
78→}
