package email

import (
	"database/sql"
	"testing"

	"github.com/usenurge/nurgesh/internal/db"
	_ "modernc.org/sqlite"
)

func setupTestDB(t *testing.T) *sql.DB {
	t.Helper()
	d, err := sql.Open("sqlite", ":memory:")
	if err != nil {
		t.Fatal(err)
	}
	if _, err := d.Exec(db.Schema); err != nil {
		t.Fatal(err)
	}
	return d
}

func seedEmails(t *testing.T, d *sql.DB) {
	t.Helper()
	d.Exec(`INSERT INTO emails (id, thread_id, subject, from_email, to_emails, date, class) VALUES
		('1', 't1', 'Sales pitch', 'me@co.com', '["cto@target.com"]', '2026-03-20T10:00:00Z', 'outbound'),
		('2', 't2', 'Team standup', 'me@co.com', '["team@co.com"]', '2026-03-21T10:00:00Z', 'internal'),
		('3', 't3', 'Follow up', 'me@co.com', '["vp@target2.com"]', '2026-03-22T10:00:00Z', 'unclassified')`)
}

func TestListEmails_All(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()
	seedEmails(t, d)

	list, err := List(d, ListOptions{})
	if err != nil {
		t.Fatal(err)
	}
	if len(list) != 3 {
		t.Fatalf("expected 3 emails, got %d", len(list))
	}
}

func TestListEmails_ByClass(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()
	seedEmails(t, d)

	list, err := List(d, ListOptions{Class: "outbound"})
	if err != nil {
		t.Fatal(err)
	}
	if len(list) != 1 {
		t.Fatalf("expected 1 outbound email, got %d", len(list))
	}
}

func TestStats(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()
	seedEmails(t, d)

	stats, err := Stats(d)
	if err != nil {
		t.Fatal(err)
	}
	if stats.Total != 3 {
		t.Fatalf("expected 3 total, got %d", stats.Total)
	}
	if stats.ByClass["outbound"] != 1 {
		t.Fatalf("expected 1 outbound, got %d", stats.ByClass["outbound"])
	}
}

func TestClassify(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()
	seedEmails(t, d)

	updates := []ClassifyUpdate{
		{ID: "3", Class: "outbound", Confidence: 0.92, ClassifiedBy: "claude"},
	}

	count, err := Classify(d, updates)
	if err != nil {
		t.Fatal(err)
	}
	if count != 1 {
		t.Fatalf("expected 1 classified, got %d", count)
	}

	var class string
	d.QueryRow("SELECT class FROM emails WHERE id = '3'").Scan(&class)
	if class != "outbound" {
		t.Fatalf("expected 'outbound', got %q", class)
	}
}

func TestCheck(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()
	seedEmails(t, d)

	health, err := Check(d)
	if err != nil {
		t.Fatal(err)
	}
	if health == nil {
		t.Fatal("expected non-nil health check")
	}
}

