package cmd

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	nurgeInit "github.com/usenurge/nurgesh/internal/init"
	"github.com/spf13/cobra"
)

var (
	initCredentials string
	initSkipConnect bool
	initSkipHooks   bool
	initForce       bool
	initVerbose     bool
)

var initCmd = &cobra.Command{
	Use:         "init [directory]",
	Short:       "Initialize a nurge project",
	Long:        "Sets up .nurge/ directory, database, connectors, Claude Code hooks, and the /nurge:setup skill.",
	Args:        cobra.MaximumNArgs(1),
	Annotations: map[string]string{"skipAuth": "true"},
	RunE: func(cmd *cobra.Command, args []string) error {
		dirCreated := ""

		if len(args) == 1 {
			// nurge init <directory> — create and chdir into it
			dir := args[0]
			if err := os.MkdirAll(dir, 0755); err != nil {
				return fmt.Errorf("failed to create directory %s: %w", dir, err)
			}
			abs, err := filepath.Abs(dir)
			if err != nil {
				return err
			}
			if err := os.Chdir(abs); err != nil {
				return fmt.Errorf("failed to enter directory %s: %w", dir, err)
			}
			dirCreated = dir
		}

		// Check if current directory is non-empty (unless --force)
		if !initForce {
			empty, err := isDirEmpty(".")
			if err != nil {
				return err
			}
			if !empty {
				return fmt.Errorf("this directory isn't empty. Run: nurge init <folder-name>")
			}
		}

		opts := nurgeInit.Options{
			Credentials:    initCredentials,
			SkipConnectors: initSkipConnect,
			SkipHooks:      initSkipHooks,
			Force:          initForce,
			Verbose:        initVerbose,
		}
		if err := nurgeInit.Run(opts); err != nil {
			return err
		}

		if dirCreated != "" {
			fmt.Println()
			fmt.Printf("  Now run: cd %s\n", dirCreated)
			fmt.Println()
		}

		return nil
	},
}

// isDirEmpty returns true if dir contains no entries except allowed ones
// (.nurge, .git, .gitignore, .DS_Store, .claude).
func isDirEmpty(dir string) (bool, error) {
	allowed := map[string]bool{
		".nurge":     true,
		".git":       true,
		".gitignore": true,
		".DS_Store":  true,
		".claude":    true,
	}

	entries, err := os.ReadDir(dir)
	if err != nil {
		return false, err
	}
	for _, e := range entries {
		name := strings.TrimSuffix(e.Name(), "/")
		if !allowed[name] {
			return false, nil
		}
	}
	return true, nil
}

func init() {
	initCmd.Flags().StringVar(&initCredentials, "credentials", "", "Path to OAuth credentials.json for Gmail (default: bundled)")
	initCmd.Flags().BoolVar(&initSkipConnect, "skip-connectors", false, "Skip the connector step")
	initCmd.Flags().BoolVar(&initSkipHooks, "skip-hooks", false, "Skip Claude Code hook installation")
	initCmd.Flags().BoolVar(&initForce, "force", false, "Re-run all steps even if already completed")
	initCmd.Flags().BoolVar(&initVerbose, "verbose", false, "Show detailed output")

	rootCmd.AddCommand(initCmd)
}

