		}

		// Validate against Convex
		client := NewConvexClient(convexURL)
		user, valErr := client.ValidateToken(af.Token)
		if valErr == nil {
			// Update validated_at
			af.ValidatedAt = time.Now().UTC().Format(time.RFC3339)
			SaveAuth(af) // best effort
			return user, nil
		}

		// Distinguish: token definitively invalid vs network error
		if errors.Is(valErr, ErrTokenInvalid) {
			// Token is invalid on server — go straight to login, no grace period
			return Login(convexURL, dashboardURL)
		}

		// Network error — check grace period
		if af.ValidatedAt != "" {
			validatedAt, _ := time.Parse(time.RFC3339, af.ValidatedAt)
			if time.Since(validatedAt) < gracePeriod {
				fmt.Fprintf(os.Stderr, "  Warning: could not reach Nurge servers, using cached auth\n")
				return &User{Email: af.Email, Name: af.Name}, nil
			}
		}

