// Login runs the interactive browser-based login flow.
func Login(convexURL, dashboardURL string) (*User, error) {
	// Generate state parameter
	state := generateState()

	// Start local callback server (binds before opening browser)
	port, resultCh, errCh, cleanup, err := callbackserver.ListenAndWait(loginTimeout)
	if err != nil {
		return nil, fmt.Errorf("starting callback server: %w", err)
	}
	defer cleanup()

	// Open browser to dashboard
	authURL := fmt.Sprintf("%s/cli-auth?port=%d&state=%s", dashboardURL, port, state)
	fmt.Fprintf(os.Stderr, "  Opening browser to log in...\n")
	if err := browser.Open(authURL); err != nil {
		fmt.Fprintf(os.Stderr, "  Could not open browser. Please visit:\n  %s\n", authURL)
	}

	// Wait for callback
	select {
	case result := <-resultCh:
		// Verify state
		if result.Values.Get("state") != state {
			return nil, fmt.Errorf("state mismatch — possible CSRF attack")
		}

		code := result.Values.Get("code")
		if code == "" {
			return nil, fmt.Errorf("no auth code received")
		}

		// Exchange code for token
		client := NewConvexClient(convexURL)
		resp, err := client.ExchangeCode(code)
		if err != nil {
			return nil, fmt.Errorf("exchanging auth code: %w", err)
		}

		// Save auth file
		now := time.Now().UTC().Format(time.RFC3339)
		af := &AuthFile{
			Token:       resp.Token,
			Email:       resp.Email,
			Name:        resp.Name,
			CreatedAt:   now,
			ValidatedAt: now,
		}
		if err := SaveAuth(af); err != nil {
			return nil, fmt.Errorf("saving auth: %w", err)
		}

		fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Logged in as %s\n", resp.Email)
		return &User{Email: resp.Email, Name: resp.Name}, nil

	case err := <-errCh:
		return nil, err
	}
}

// Logout revokes the token and deletes local auth file.
func Logout(convexURL string) error {
	af, err := LoadAuth()
	if err != nil {
		return fmt.Errorf("not logged in")
	}

	// Revoke on server (best effort)
	client := NewConvexClient(convexURL)
	_ = client.RevokeToken(af.Token)

	// Delete local auth file
	if err := DeleteAuth(); err != nil {
		return fmt.Errorf("deleting auth file: %w", err)
	}

	fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Logged out\n")
	return nil
}

// generateState creates a cryptographically random state string for CSRF protection.
func generateState() string {
	const chars = "REDACTED"
	b := make([]byte, 32)
	for i := range b {
		n, _ := rand.Int(rand.Reader, big.NewInt(int64(len(chars))))
		b[i] = chars[n.Int64()]
	}
	return string(b)
}

