 16→)
 17→
 18→func newCleanCmd() *cobra.Command {
 19→	var forceFlag bool
 20→
 21→	cmd := &cobra.Command{
 22→		Use:   "clean",
 23→		Short: "Clean up orphaned Entire data",
 24→		Long: `Remove orphaned Entire data (session state, shadow branches, checkpoint metadata, temp files) that wasn't cleaned up automatically.
 25→
 26→This command finds and removes orphaned data from any strategy:
 27→
 28→  Shadow branches (entire/<commit-hash>)
 29→    Normally auto-cleaned when sessions
 30→    are condensed during commits.
 31→
 32→  Session state files (.git/entire-sessions/)
 33→    Track active sessions. Orphaned when no checkpoints or shadow branches
 34→    reference them.
 35→
 36→  Checkpoint metadata (entire/checkpoints/v1 branch)
 37→    Checkpoints are permanent (condensed session history) and are
 38→    never considered orphaned.
 39→
 40→  Temporary files (.entire/tmp/)
 41→    Cached transcripts and other temporary data. Safe to delete when no
 42→    active sessions are using them.
 43→
 44→Default: shows a preview and asks for confirmation before deleting.
 45→With --force, deletes without prompting.
 46→
 47→The entire/checkpoints/v1 branch itself is never deleted.`,
 48→		RunE: func(cmd *cobra.Command, _ []string) error {
 49→			return runClean(cmd.Context(), cmd, forceFlag)
 50→		},
 51→	}
 52→
 53→	cmd.Flags().BoolVarP(&forceFlag, "force", "f", false, "Delete without prompting for confirmation")
 54→
 55→	return cmd
 56→}
 57→
 58→func runClean(ctx context.Context, cmd *cobra.Command, force bool) error {
 59→	w := cmd.OutOrStdout()
 60→	errW := cmd.ErrOrStderr()
 61→
 62→	// Initialize logging so structured logs go to .entire/logs/ instead of stderr.
 63→	// Error is non-fatal: if logging init fails, logs go to stderr (acceptable fallback).
 64→	logging.SetLogLevelGetter(GetLogLevel)
 65→	if err := logging.Init(ctx, ""); err == nil {
 66→		defer logging.Close()
 67→	}
 68→
 69→	// List all cleanup items
 70→	items, err := strategy.ListAllCleanupItems(ctx)
 71→	if err != nil {
 72→		return fmt.Errorf("failed to list orphaned items: %w", err)
 73→	}
 74→
 75→	// List temp files
 76→	tempFiles, err := listTempFiles(ctx)
 77→	if err != nil {
 78→		// Non-fatal: continue with other cleanup items
 79→		fmt.Fprintf(errW, "Warning: failed to list temp files: %v\n", err)
 80→	}
 81→
 82→	// Force mode: skip preview and confirmation
 83→	if force {
 84→		return runCleanWithItems(ctx, w, true, items, tempFiles)
 85→	}
 86→
 87→	// Show preview
 88→	if err := runCleanWithItems(ctx, w, false, items, tempFiles); err != nil {
 89→		return err
 90→	}
 91→
 92→	// If nothing to clean, we're done (preview already printed the message)
 93→	totalItems := len(items) + len(tempFiles)
 94→	if totalItems == 0 {
 95→		return nil
 96→	}
 97→
 98→	// Interactive confirmation
 99→	var confirmed bool
100→	form := NewAccessibleForm(
101→		huh.NewGroup(
102→			huh.NewConfirm().
103→				Title("Delete these items?").
104→				Affirmative("Yes, delete").
105→				Negative("Cancel").
106→				Value(&confirmed),
107→		),
108→	)
109→
110→	if err := form.Run(); err != nil {
111→		return handleFormCancellation(w, "Clean", err)
112→	}
113→
114→	if !confirmed {
115→		fmt.Fprintln(w, "Clean cancelled.")
116→		return nil
117→	}
118→
119→	return runCleanWithItems(ctx, w, true, items, tempFiles)
120→}
121→
122→// listTempFiles returns files in .entire/tmp/ that are safe to delete,
123→// excluding files belonging to active sessions.
124→func listTempFiles(ctx context.Context) ([]string, error) {
125→	tmpDir, err := paths.AbsPath(ctx, paths.EntireTmpDir)
126→	if err != nil {
127→		return nil, fmt.Errorf("failed to get temp dir path: %w", err)
128→	}
129→
130→	entries, err := os.ReadDir(tmpDir)
131→	if os.IsNotExist(err) {
132→		return nil, nil
133→	}
134→	if err != nil {
135→		return nil, fmt.Errorf("failed to read temp dir: %w", err)
136→	}
137→
138→	// Build set of active session IDs to protect their temp files
139→	activeSessionIDs := make(map[string]bool)
140→	if states, listErr := strategy.ListSessionStates(ctx); listErr == nil {
141→		for _, state := range states {
142→			activeSessionIDs[state.SessionID] = true
143→		}
144→	}
145→
146→	var files []string
147→	for _, entry := range entries {
148→		if entry.IsDir() {
149→			continue
150→		}
151→		// Skip temp files belonging to active sessions (e.g., "session-id.json")
152→		name := entry.Name()
153→		sessionID := strings.TrimSuffix(name, ".json")
154→		if sessionID != name && activeSessionIDs[sessionID] {
155→			continue
156→		}
157→		files = append(files, name)
158→	}
159→	return files, nil
160→}
