162→// TempFileDeleteError contains a file name and the error that occurred during deletion.
163→type TempFileDeleteError struct {
164→	File string
165→	Err  error
166→}
167→
168→// deleteTempFiles removes all files in .entire/tmp/.
169→// Returns successfully deleted files and any failures with their error reasons.
170→func deleteTempFiles(ctx context.Context, files []string) (deleted []string, failed []TempFileDeleteError) {
171→	tmpDir, err := paths.AbsPath(ctx, paths.EntireTmpDir)
172→	if err != nil {
173→		// Can't get path - mark all as failed with the same error
174→		for _, file := range files {
175→			failed = append(failed, TempFileDeleteError{File: file, Err: err})
176→		}
177→		return nil, failed
178→	}
179→
180→	for _, file := range files {
181→		path := filepath.Join(tmpDir, file)
182→		if err := os.Remove(path); err != nil {
183→			failed = append(failed, TempFileDeleteError{File: file, Err: err})
184→		} else {
185→			deleted = append(deleted, file)
186→		}
187→	}
188→	return deleted, failed
189→}
