191→// runCleanWithItems is the core logic for cleaning orphaned items.
192→// Separated for testability.
193→func runCleanWithItems(ctx context.Context, w io.Writer, force bool, items []strategy.CleanupItem, tempFiles []string) error {
194→	// Handle no items case
