220→			for _, item := range branches {
221→				fmt.Fprintf(w, "  %s\n", item.ID)
222→			}
223→			fmt.Fprintln(w)
224→		}
225→
226→		if len(states) > 0 {
227→			fmt.Fprintf(w, "Session states (%d):\n", len(states))
228→			for _, item := range states {
229→				fmt.Fprintf(w, "  %s\n", item.ID)
230→			}
231→			fmt.Fprintln(w)
232→		}
233→
234→		if len(checkpoints) > 0 {
235→			fmt.Fprintf(w, "Checkpoint metadata (%d):\n", len(checkpoints))
236→			for _, item := range checkpoints {
237→				fmt.Fprintf(w, "  %s\n", item.ID)
238→			}
239→			fmt.Fprintln(w)
240→		}
241→
242→		if len(tempFiles) > 0 {
243→			fmt.Fprintf(w, "Temp files (%d):\n", len(tempFiles))
244→			for _, file := range tempFiles {
245→				fmt.Fprintf(w, "  %s\n", file)
246→			}
247→			fmt.Fprintln(w)
248→		}
249→
250→		fmt.Fprintln(w, "Use --force to skip this prompt.")
251→		return nil
252→	}
253→
254→	// Force mode - delete items
255→	result, err := strategy.DeleteAllCleanupItems(ctx, items)
256→	if err != nil {
257→		return fmt.Errorf("failed to delete orphaned items: %w", err)
258→	}
259→
260→	// Delete temp files
261→	deletedTempFiles, failedTempFiles := deleteTempFiles(ctx, tempFiles)
262→
263→	// Report results
264→	totalDeleted := len(result.ShadowBranches) + len(result.SessionStates) + len(result.Checkpoints) + len(deletedTempFiles)
265→	totalFailed := len(result.FailedBranches) + len(result.FailedStates) + len(result.FailedCheckpoints) + len(failedTempFiles)
266→
267→	if totalDeleted > 0 {
268→		fmt.Fprintf(w, "✓ Deleted %d %s:\n", totalDeleted, itemWord(totalDeleted))
269→
270→		if len(result.ShadowBranches) > 0 {
271→			fmt.Fprintf(w, "\nShadow branches (%d):\n", len(result.ShadowBranches))
272→			for _, branch := range result.ShadowBranches {
273→				fmt.Fprintf(w, "  %s\n", branch)
274→			}
275→		}
276→
277→		if len(result.SessionStates) > 0 {
278→			fmt.Fprintf(w, "\nSession states (%d):\n", len(result.SessionStates))
279→			for _, state := range result.SessionStates {
280→				fmt.Fprintf(w, "  %s\n", state)
281→			}
282→		}
283→
284→		if len(result.Checkpoints) > 0 {
285→			fmt.Fprintf(w, "\nCheckpoints (%d):\n", len(result.Checkpoints))
286→			for _, cp := range result.Checkpoints {
287→				fmt.Fprintf(w, "  %s\n", cp)
288→			}
289→		}
290→
291→		if len(deletedTempFiles) > 0 {
292→			fmt.Fprintf(w, "\nTemp files (%d):\n", len(deletedTempFiles))
293→			for _, file := range deletedTempFiles {
294→				fmt.Fprintf(w, "  %s\n", file)
295→			}
296→		}
297→	}
298→
299→	if totalFailed > 0 {
300→		fmt.Fprintf(w, "\nFailed to delete %d %s:\n", totalFailed, itemWord(totalFailed))
301→
302→		if len(result.FailedBranches) > 0 {
303→			fmt.Fprintf(w, "\nShadow branches:\n")
304→			for _, branch := range result.FailedBranches {
305→				fmt.Fprintf(w, "  %s\n", branch)
306→			}
307→		}
308→
309→		if len(result.FailedStates) > 0 {
310→			fmt.Fprintf(w, "\nSession states:\n")
311→			for _, state := range result.FailedStates {
312→				fmt.Fprintf(w, "  %s\n", state)
313→			}
314→		}
315→
316→		if len(result.FailedCheckpoints) > 0 {
317→			fmt.Fprintf(w, "\nCheckpoints:\n")
318→			for _, cp := range result.FailedCheckpoints {
319→				fmt.Fprintf(w, "  %s\n", cp)
320→			}
321→		}
322→
323→		if len(failedTempFiles) > 0 {
324→			fmt.Fprintf(w, "\nTemp files:\n")
325→			for _, fe := range failedTempFiles {
326→				fmt.Fprintf(w, "  %s: %v\n", fe.File, fe.Err)
327→			}
328→		}
329→
330→		return fmt.Errorf("failed to delete %d %s", totalFailed, itemWord(totalFailed))
331→	}
332→
333→	return nil
334→}
