 42→func runStatus(ctx context.Context, w io.Writer, detailed bool) error {
 43→	// Check if we're in a git repository
 44→	if _, repoErr := paths.WorktreeRoot(ctx); repoErr != nil {
 45→		fmt.Fprintln(w, "✕ not a git repository")
 46→		return nil //nolint:nilerr // Not being in a git repo is a valid status, not an error
 47→	}
 48→
 49→	// Get absolute paths for settings files
 50→	settingsPath, err := paths.AbsPath(ctx, EntireSettingsFile)
 51→	if err != nil {
 52→		settingsPath = EntireSettingsFile
 53→	}
 54→	localSettingsPath, err := paths.AbsPath(ctx, EntireSettingsLocalFile)
 55→	if err != nil {
 56→		localSettingsPath = EntireSettingsLocalFile
 57→	}
 58→
 59→	// Check which settings files exist
 60→	_, projectErr := os.Stat(settingsPath)
 61→	if projectErr != nil && !errors.Is(projectErr, fs.ErrNotExist) {
 62→		return fmt.Errorf("cannot access project settings file: %w", projectErr)
 63→	}
 64→	_, localErr := os.Stat(localSettingsPath)
 65→	if localErr != nil && !errors.Is(localErr, fs.ErrNotExist) {
 66→		return fmt.Errorf("cannot access local settings file: %w", localErr)
 67→	}
 68→	projectExists := projectErr == nil
 69→	localExists := localErr == nil
 70→
 71→	if !projectExists && !localExists {
 72→		fmt.Fprintln(w, "○ not set up (run `entire enable` to get started)")
 73→		return nil
 74→	}
 75→
 76→	sty := newStatusStyles(w)
 77→
 78→	if detailed {
 79→		return runStatusDetailed(ctx, w, sty, settingsPath, localSettingsPath, projectExists, localExists)
 80→	}
 81→
 82→	// Short output: just show the effective/merged state
 83→	s, err := LoadEntireSettings(ctx)
 84→	if err != nil {
 85→		return fmt.Errorf("failed to load settings: %w", err)
 86→	}
 87→
 88→	fmt.Fprintln(w)
 89→	fmt.Fprintln(w)
 90→	fmt.Fprintln(w, formatSettingsStatusShort(ctx, s, sty))
 91→	if s.Enabled {
 92→		writeActiveSessions(ctx, w, sty)
 93→	}
 94→
 95→	return nil
 96→}
