188→// timeAgo formats a time as a human-readable relative duration.
189→func timeAgo(t time.Time) string {
190→	d := time.Since(t)
191→	switch {
192→	case d < time.Minute:
193→		return "just now"
194→	case d < time.Hour:
195→		m := int(d.Minutes())
196→		return fmt.Sprintf("%dm ago", m)
197→	case d < 24*time.Hour:
198→		h := int(d.Hours())
199→		return fmt.Sprintf("%dh ago", h)
200→	default:
201→		days := int(d.Hours() / 24)
202→		return fmt.Sprintf("%dd ago", days)
203→	}
204→}
