206→// worktreeGroup groups sessions by worktree path for display.
207→type worktreeGroup struct {
208→	path     string
209→	branch   string
210→	sessions []*session.State
211→}
212→
213→const (
214→	unknownPlaceholder  = "(unknown)"
215→	detachedHEADDisplay = "HEAD"
216→)
