218→// writeActiveSessions writes active session information grouped by worktree.
219→func writeActiveSessions(ctx context.Context, w io.Writer, sty statusStyles) {
220→	store, err := session.NewStateStore(ctx)
221→	if err != nil {
222→		return
223→	}
224→
225→	states, err := store.List(ctx)
226→	if err != nil || len(states) == 0 {
227→		return
228→	}
229→
230→	// Filter to active sessions only
231→	var active []*session.State
232→	for _, s := range states {
233→		if s.EndedAt == nil {
234→			active = append(active, s)
235→		}
236→	}
237→	if len(active) == 0 {
238→		return
239→	}
240→
241→	// Group by worktree path
242→	groups := make(map[string]*worktreeGroup)
243→	for _, s := range active {
244→		wp := s.WorktreePath
245→		if wp == "" {
246→			wp = unknownPlaceholder
247→		}
248→		g, ok := groups[wp]
249→		if !ok {
250→			g = &worktreeGroup{path: wp}
251→			groups[wp] = g
252→		}
253→		g.sessions = append(g.sessions, s)
254→	}
255→
256→	// Resolve branch names for each worktree (skip for unknown paths)
257→	for _, g := range groups {
258→		if g.path != unknownPlaceholder {
259→			g.branch = resolveWorktreeBranch(ctx, g.path)
260→		}
261→	}
262→
263→	// Sort groups: alphabetical by path
264→	sortedGroups := make([]*worktreeGroup, 0, len(groups))
265→	for _, g := range groups {
266→		sortedGroups = append(sortedGroups, g)
267→	}
268→	sort.Slice(sortedGroups, func(i, j int) bool {
269→		return sortedGroups[i].path < sortedGroups[j].path
270→	})
271→
272→	// Sort sessions within each group by StartedAt (newest first)
273→	for _, g := range sortedGroups {
274→		sort.Slice(g.sessions, func(i, j int) bool {
275→			return g.sessions[i].StartedAt.After(g.sessions[j].StartedAt)
276→		})
277→	}
278→
279→	// Track aggregate totals
280→	var totalSessions int
281→
282→	fmt.Fprintln(w)
283→	printedHeader := false
284→	for _, g := range sortedGroups {
285→		if !printedHeader {
286→			fmt.Fprintln(w, sty.sectionRule("Active Sessions", sty.width))
287→			fmt.Fprintln(w)
288→			printedHeader = true
289→		}
290→
291→		for _, st := range g.sessions {
292→			totalSessions++
293→
294→			agentLabel := string(st.AgentType)
295→			if agentLabel == "" {
296→				agentLabel = unknownPlaceholder
297→			}
298→
299→			// Line 1: Agent (model) · sessionID
300→			if st.ModelName != "" {
301→				fmt.Fprintf(w, "%s %s %s %s\n",
302→					sty.render(sty.agent, agentLabel),
303→					sty.render(sty.dim, "("+st.ModelName+")"),
304→					sty.render(sty.dim, "·"),
305→					st.SessionID)
306→			} else {
307→				fmt.Fprintf(w, "%s %s %s\n",
308→					sty.render(sty.agent, agentLabel),
309→					sty.render(sty.dim, "·"),
310→					st.SessionID)
311→			}
312→
313→			// Line 2: > "first prompt" (chevron + quoted, truncated)
314→			if st.LastPrompt != "" {
315→				prompt := stringutil.TruncateRunes(st.LastPrompt, 60, "...")
316→				fmt.Fprintf(w, "%s \"%s\"\n", sty.render(sty.dim, ">"), prompt)
317→			}
318→
319→			// Line 3: stats line — started Xd ago · active now · files N · tokens X.Xk
320→			var stats []string
321→			stats = append(stats, "started "+timeAgo(st.StartedAt))
322→
323→			if st.LastInteractionTime != nil && st.LastInteractionTime.Sub(st.StartedAt) > time.Minute {
324→				stats = append(stats, activeTimeDisplay(st.LastInteractionTime))
325→			}
326→
327→			stats = append(stats, "tokens "+formatTokenCount(totalTokens(st.TokenUsage)))
328→
329→			statsLine := strings.Join(stats, sty.render(sty.dim, " · "))
330→			fmt.Fprintln(w, sty.render(sty.dim, statsLine))
331→			fmt.Fprintln(w)
332→		}
333→	}
334→
335→	// Footer: horizontal rule + session count
336→	fmt.Fprintln(w, sty.horizontalRule(sty.width))
337→	var footer string
338→	if totalSessions == 1 {
339→		footer = "1 session"
340→	} else {
341→		footer = fmt.Sprintf("%d sessions", totalSessions)
342→	}
343→	fmt.Fprintln(w, sty.render(sty.dim, footer))
344→	fmt.Fprintln(w)
345→}
