347→// resolveWorktreeBranch resolves the current branch for a worktree path
348→// by reading the HEAD ref directly from the filesystem
349→func resolveWorktreeBranch(ctx context.Context, worktreePath string) string {
350→	gitPath := filepath.Join(worktreePath, ".git")
351→
352→	fi, err := os.Stat(gitPath)
353→	if err != nil {
354→		return ""
355→	}
356→
357→	var headPath string
358→	if fi.IsDir() {
359→		// Regular repo: .git is a directory
360→		headPath = filepath.Join(gitPath, "HEAD")
361→	} else {
362→		// Worktree: .git is a file containing "gitdir: <path>"
363→		data, err := os.ReadFile(gitPath) //nolint:gosec // path derived from known worktree dir
364→		if err != nil {
365→			return ""
366→		}
367→		content := strings.TrimSpace(string(data))
368→		if !strings.HasPrefix(content, "gitdir: ") {
369→			return ""
370→		}
371→		gitdirPath := strings.TrimPrefix(content, "gitdir: ")
372→		if !filepath.IsAbs(gitdirPath) {
373→			gitdirPath = filepath.Join(worktreePath, gitdirPath)
374→		}
375→		headPath = filepath.Join(gitdirPath, "HEAD")
376→	}
377→
378→	data, err := os.ReadFile(headPath) //nolint:gosec // path constructed from .git/HEAD
379→	if err != nil {
380→		return ""
381→	}
382→
383→	ref := strings.TrimSpace(string(data))
384→
385→	// Symbolic ref: "ref: refs/heads/<branch>"
386→	if strings.HasPrefix(ref, "ref: refs/heads/") {
387→		branch := strings.TrimPrefix(ref, "ref: refs/heads/")
388→		// Reftable ref storage uses "ref: refs/heads/.invalid" as a dummy HEAD stub.
389→		// Fall back to git to resolve the actual branch in that case.
390→		if branch == ".invalid" {
391→			return resolveWorktreeBranchGit(ctx, worktreePath)
392→		}
393→		return branch
394→	}
395→
396→	// Detached HEAD or other ref type
397→	return detachedHEADDisplay
398→}
399→
400→// resolveWorktreeBranchGit resolves the branch name by shelling out to git.
401→// Used as a fallback for reftable ref storage where .git/HEAD is a stub.
402→func resolveWorktreeBranchGit(ctx context.Context, worktreePath string) string {
403→	ctx, cancel := context.WithTimeout(ctx, 5*time.Second)
404→	defer cancel()
405→	cmd := exec.CommandContext(ctx, "git", "-C", worktreePath, "rev-parse", "--symbolic-full-name", "HEAD")
406→	out, err := cmd.Output()
407→	if err != nil {
408→		return detachedHEADDisplay
409→	}
410→	ref := strings.TrimSpace(string(out))
411→	if strings.HasPrefix(ref, "refs/heads/") {
412→		return strings.TrimPrefix(ref, "refs/heads/")
413→	}
414→	return detachedHEADDisplay
415→}
