 63→func runLogin(ctx context.Context, outW, errW io.Writer, client deviceAuthClient, openURL browserOpenFunc) error {
 64→	start, err := client.StartDeviceAuth(ctx)
 65→	if err != nil {
 66→		return fmt.Errorf("start login: %w", err)
 67→	}
 68→
 69→	fmt.Fprintf(outW, "Device code: %s\n", start.UserCode)
 70→	approvalURL := start.VerificationURI
 71→	if approvalURL == "" {
 72→		approvalURL = start.VerificationURIComplete
 73→	}
 74→
 75→	if canPromptInteractively() {
 76→		fmt.Fprintf(outW, "Press Enter to open %s in your browser...", approvalURL)
 77→
 78→		// Read from /dev/tty so we get a real keypress and don't consume piped stdin.
 79→		waitForEnter()
 80→
 81→		fmt.Fprintln(outW)
 82→
 83→		if err := openURL(ctx, approvalURL); err != nil {
 84→			fmt.Fprintf(errW, "Warning: failed to open browser: %v\n", err)
 85→			fmt.Fprintln(outW, "Open the approval URL in your browser to continue.")
 86→		}
 87→	} else {
 88→		fmt.Fprintf(outW, "Approval URL: %s\n", approvalURL)
 89→	}
 90→
 91→	fmt.Fprintln(outW, "Waiting for approval...")
 92→
 93→	token, err := waitForApproval(ctx, client, start.DeviceCode, start.ExpiresIn, start.Interval)
 94→	if err != nil {
 95→		return fmt.Errorf("complete login: %w", err)
 96→	}
 97→
 98→	store := auth.NewStore()
 99→
100→	if err := store.SaveToken(client.BaseURL(), token); err != nil {
101→		return fmt.Errorf("save auth token: %w", err)
102→	}
103→
104→	fmt.Fprintln(outW, "Login complete.")
105→	return nil
106→}
