108→func waitForApproval(ctx context.Context, poller deviceAuthClient, deviceCode string, expiresIn, interval int) (string, error) {
109→	expiry := time.Duration(expiresIn) * time.Second
110→	if expiry <= 0 || expiry > maxExpiresIn {
111→		expiry = maxExpiresIn
112→	}
113→	deadline := time.Now().Add(expiry)
114→	pollInterval := time.Duration(interval) * time.Second
115→	if pollInterval <= 0 {
116→		pollInterval = fallbackDeviceAuthPollInterval
117→	}
118→
119→	consecutiveErrors := 0
120→
121→	for {
122→		if time.Now().After(deadline) {
123→			return "", errors.New("device authorization expired")
124→		}
125→
126→		result, err := poller.PollDeviceAuth(ctx, deviceCode)
127→		if err != nil {
128→			consecutiveErrors++
129→			if consecutiveErrors >= maxTransientErrors {
130→				return "", fmt.Errorf("poll approval status (after %d consecutive failures): %w", consecutiveErrors, err)
131→			}
132→			// Transient error — wait and retry.
133→			select {
134→			case <-ctx.Done():
135→				return "", fmt.Errorf("wait for approval: %w", ctx.Err())
136→			case <-time.After(pollInterval):
137→			}
138→			continue
139→		}
140→		consecutiveErrors = 0
141→
142→		switch result.Error {
143→		case "":
144→			if result.AccessToken == "" {
145→				return "", errors.New("device authorization completed without a token")
146→			}
147→			return result.AccessToken, nil
148→		case "authorization_pending":
149→			// no-op, will sleep and retry below
150→		case "slow_down":
151→			pollInterval += slowDownBackoff
152→			if pollInterval > maxPollInterval {
153→				pollInterval = maxPollInterval
154→			}
155→		case "access_denied":
156→			return "", errors.New("device authorization denied")
157→		case "expired_token":
158→			return "", errors.New("device authorization expired")
159→		default:
160→			return "", fmt.Errorf("device authorization failed: %s", result.Error)
161→		}
162→
163→		select {
164→		case <-ctx.Done():
165→			return "", fmt.Errorf("wait for approval: %w", ctx.Err())
166→		case <-time.After(pollInterval):
167→		}
168→	}
169→}
