171→// waitForEnter reads a line from /dev/tty, blocking until the user presses Enter.
172→// If /dev/tty cannot be opened (e.g. on Windows), it returns immediately.
173→func waitForEnter() {
174→	tty, err := os.Open("/dev/tty")
175→	if err != nil {
176→		return
177→	}
178→	defer tty.Close()
179→
180→	reader := bufio.NewReader(tty)
181→	if _, err = reader.ReadString('\n'); err != nil {
182→		return
183→	}
184→}
