186→func openBrowser(ctx context.Context, browserURL string) error {
187→	u, err := url.Parse(browserURL)
188→	if err != nil || (u.Scheme != "https" && u.Scheme != "http") {
189→		return fmt.Errorf("refusing to open non-HTTP URL: %s", browserURL)
190→	}
191→
192→	var command string
193→	var args []string
194→
195→	switch runtime.GOOS {
196→	case "darwin":
197→		command = "open"
198→		args = []string{browserURL}
199→	case "linux":
200→		command = "xdg-open"
201→		args = []string{browserURL}
202→	case "windows":
203→		command = "cmd"
204→		args = []string{"/c", "start", "", browserURL}
205→	default:
206→		return fmt.Errorf("unsupported platform %s", runtime.GOOS)
207→	}
208→
209→	cmd := exec.CommandContext(ctx, command, args...)
210→	if err := cmd.Start(); err != nil {
211→		return fmt.Errorf("start browser command %q: %w", command, err)
212→	}
213→
214→	if err := cmd.Process.Release(); err != nil {
215→		return fmt.Errorf("release browser process: %w", err)
216→	}
217→
218→	return nil
219→}
