 54→// DetectPresence checks if Claude Code is configured in the repository.
 55→func (c *ClaudeCodeAgent) DetectPresence(ctx context.Context) (bool, error) {
 56→	// Get worktree root to check for .claude directory
 57→	// This is needed because the CLI may be run from a subdirectory
 58→	repoRoot, err := paths.WorktreeRoot(ctx)
 59→	if err != nil {
 60→		// Not in a git repo, fall back to CWD-relative check
 61→		repoRoot = "."
 62→	}
 63→
 64→	// Check for .claude directory
 65→	claudeDir := filepath.Join(repoRoot, ".claude")
 66→	if _, err := os.Stat(claudeDir); err == nil {
 67→		return true, nil
 68→	}
 69→	// Check for .claude/settings.json
 70→	settingsFile := filepath.Join(repoRoot, ".claude", "settings.json")
 71→	if _, err := os.Stat(settingsFile); err == nil {
 72→		return true, nil
 73→	}
 74→	return false, nil
 75→}
