107→// ReadSession reads a session from Claude's storage (JSONL transcript file).
108→// The session data is stored in NativeData as raw JSONL bytes.
109→// ModifiedFiles is computed by parsing the transcript.
110→func (c *ClaudeCodeAgent) ReadSession(input *agent.HookInput) (*agent.AgentSession, error) {
111→	if input.SessionRef == "" {
112→		return nil, errors.New("session reference (transcript path) is required")
113→	}
114→
115→	// Read the raw JSONL file
116→	data, err := os.ReadFile(input.SessionRef)
117→	if err != nil {
118→		return nil, fmt.Errorf("failed to read transcript: %w", err)
119→	}
120→
121→	// Parse to extract computed fields
122→	lines, err := transcript.ParseFromBytes(data)
123→	if err != nil {
124→		return nil, fmt.Errorf("failed to parse transcript: %w", err)
125→	}
126→
127→	return &agent.AgentSession{
128→		SessionID:     input.SessionID,
129→		AgentName:     c.Name(),
130→		SessionRef:    input.SessionRef,
131→		StartTime:     time.Now(),
132→		NativeData:    data,
133→		ModifiedFiles: ExtractModifiedFiles(lines),
134→	}, nil
135→}
