137→// WriteSession writes a session to Claude's storage (JSONL transcript file).
138→// Uses the NativeData field which contains raw JSONL bytes.
139→// The session must have been created by Claude Code (AgentName check).
140→func (c *ClaudeCodeAgent) WriteSession(_ context.Context, session *agent.AgentSession) error {
141→	if session == nil {
142→		return errors.New("session is nil")
143→	}
144→
145→	// Verify this session belongs to Claude Code
146→	if session.AgentName != "" && session.AgentName != c.Name() {
147→		return fmt.Errorf("session belongs to agent %q, not %q", session.AgentName, c.Name())
148→	}
149→
150→	if session.SessionRef == "" {
151→		return errors.New("session reference (transcript path) is required")
152→	}
153→
154→	if len(session.NativeData) == 0 {
155→		return errors.New("session has no native data to write")
156→	}
157→
158→	// Write the raw JSONL data
159→	if err := os.WriteFile(session.SessionRef, session.NativeData, 0o600); err != nil {
160→		return fmt.Errorf("failed to write transcript: %w", err)
161→	}
162→
163→	return nil
164→}
