173→// TruncateAtUUID returns a new session truncated at the given UUID (inclusive).
174→// This is used for rewind operations to restore transcript state.
175→// Requires NativeData to be populated.
176→func (c *ClaudeCodeAgent) TruncateAtUUID(session *agent.AgentSession, uuid string) (*agent.AgentSession, error) {
177→	if session == nil {
178→		return nil, errors.New("session is nil")
179→	}
180→
181→	if len(session.NativeData) == 0 {
182→		return nil, errors.New("session has no native data")
183→	}
184→
185→	if uuid == "" {
186→		// No truncation needed, return copy
187→		return &agent.AgentSession{
188→			SessionID:     session.SessionID,
189→			AgentName:     session.AgentName,
190→			RepoPath:      session.RepoPath,
191→			SessionRef:    session.SessionRef,
192→			StartTime:     session.StartTime,
193→			NativeData:    session.NativeData,
194→			ModifiedFiles: session.ModifiedFiles,
195→		}, nil
196→	}
197→
198→	// Parse, truncate, re-serialize
199→	lines, err := transcript.ParseFromBytes(session.NativeData)
200→	if err != nil {
201→		return nil, fmt.Errorf("failed to parse transcript: %w", err)
202→	}
203→
204→	truncated := TruncateAtUUID(lines, uuid)
205→
206→	newData, err := SerializeTranscript(truncated)
207→	if err != nil {
208→		return nil, fmt.Errorf("failed to serialize truncated transcript: %w", err)
209→	}
210→
211→	return &agent.AgentSession{
212→		SessionID:     session.SessionID,
213→		AgentName:     session.AgentName,
214→		RepoPath:      session.RepoPath,
215→		SessionRef:    session.SessionRef,
216→		StartTime:     session.StartTime,
217→		NativeData:    newData,
218→		ModifiedFiles: ExtractModifiedFiles(truncated),
219→	}, nil
220→}
