 9→// NewHelpCmd creates a custom help command that supports a hidden -t flag
10→// to display the entire command tree.
11→func NewHelpCmd(rootCmd *cobra.Command) *cobra.Command {
12→	var showTree bool
13→
14→	helpCmd := &cobra.Command{
15→		Use:   "help [command]",
16→		Short: "Help about any command",
17→		Long: `Provides help for any Entire CLI subcommand.
18→Simply type '` + rootCmd.Name() + ` help [command]' for full details.`,
19→		Run: func(_ *cobra.Command, args []string) {
20→			if showTree {
21→				printCommandTree(rootCmd)
22→				return
23→			}
24→
25→			// Default help behavior
26→			targetCmd, _, err := rootCmd.Find(args)
27→			if err != nil || targetCmd == nil {
28→				targetCmd = rootCmd
29→			}
30→			targetCmd.Help() //nolint:errcheck,gosec // Help() only fails on write errors to stdout
31→		},
32→	}
33→
34→	helpCmd.Flags().BoolVarP(&showTree, "tree", "t", false, "Show full command tree")
35→	helpCmd.Flags().MarkHidden("tree") //nolint:errcheck,gosec // flag is defined above
36→
37→	return helpCmd
38→}
